const QUIZ_DATA = {

  // ══════════════════════════════════════════════════════════
  "ISO/IEC 27001": [
    { q:"¿Cuál es el objeto principal de ISO/IEC 27001?", o:["Gestionar riesgos financieros","Establecer, implementar y mejorar un SGSI","Auditar sistemas de información","Certificar productos software"], c:1, e:"ISO/IEC 27001 define los requisitos para establecer, implementar, mantener y mejorar continuamente un Sistema de Gestión de Seguridad de la Información (SGSI)." },
    { q:"¿Qué documento recoge qué controles del Anexo A son aplicables y por qué?", o:["Plan de tratamiento de riesgos","Política de seguridad","Declaración de Aplicabilidad (SoA)","Registro de activos"], c:2, e:"La Declaración de Aplicabilidad (SoA) lista todos los controles del Anexo A, indica cuáles aplican, su estado de implementación y la justificación de exclusiones." },
    { q:"¿Cuántos controles tiene el Anexo A de ISO/IEC 27001:2022?", o:["114","93","133","78"], c:1, e:"La versión 2022 redujo y reorganizó los controles a 93, agrupados en 4 secciones (organizacionales, personas, físicos y tecnológicos)." },
    { q:"¿Qué cláusula de ISO 27001 trata el liderazgo y compromiso de la alta dirección?", o:["Cláusula 4","Cláusula 5","Cláusula 6","Cláusula 7"], c:1, e:"La cláusula 5 (Liderazgo) establece las responsabilidades de la alta dirección: demostrar liderazgo, establecer la política y asignar roles." },
    { q:"¿Qué principio de seguridad de la información NO forma parte de la tríada CIA?", o:["Confidencialidad","Integridad","Autenticación","Disponibilidad"], c:2, e:"La tríada CIA son Confidencialidad, Integridad y Disponibilidad. La autenticación es un concepto relacionado pero no forma parte de la tríada base." },
    { q:"¿Cuál es el ciclo de mejora continua que sustenta ISO 27001?", o:["DMAIC","PDCA (Plan-Do-Check-Act)","OODA Loop","Six Sigma"], c:1, e:"ISO 27001 se basa en el ciclo PDCA: Planificar (establecer), Hacer (implementar), Verificar (monitorizar) y Actuar (mejorar)." },
    { q:"¿Qué norma complementa a ISO 27001 con guía de implementación de controles?", o:["ISO 27005","ISO 27002","ISO 31000","ISO 22301"], c:1, e:"ISO/IEC 27002 proporciona directrices de referencia para seleccionar e implementar los controles listados en el Anexo A de ISO 27001." },
    { q:"¿Qué debe incluir obligatoriamente la política de seguridad de la información?", o:["Lista de activos críticos","Objetivos y compromiso con requisitos aplicables","Presupuesto del SGSI","Procedimientos técnicos detallados"], c:1, e:"La política debe incluir los objetivos de seguridad o el marco para establecerlos, y el compromiso de cumplir requisitos aplicables y mejorar continuamente." },
    { q:"¿Cuándo debe realizarse una auditoría interna del SGSI según ISO 27001?", o:["Solo antes de la auditoría de certificación","A intervalos planificados","Únicamente tras un incidente","Cada 3 años"], c:1, e:"La cláusula 9.2 exige auditorías internas a intervalos planificados para determinar si el SGSI es conforme y se implementa eficazmente." },
    { q:"¿Qué es el 'alcance' del SGSI en ISO 27001?", o:["El presupuesto asignado a seguridad","Los límites y aplicabilidad del sistema de gestión","El número de controles implementados","La duración de la certificación"], c:1, e:"El alcance define los límites organizacionales, tecnológicos y físicos dentro de los cuales aplica el SGSI, y debe estar documentado." },
    { q:"¿Qué cláusula cubre la gestión de incidentes de seguridad en ISO 27001?", o:["Cláusula 6.1","Cláusula 8","Cláusula 9.1","Cláusula 10"], c:1, e:"La cláusula 8 (Operación) incluye la planificación y control operacional, donde se enmarcan los procesos de respuesta a incidentes." },
    { q:"¿Qué diferencia hay entre una no conformidad mayor y una menor en auditoría ISO 27001?", o:["Solo el coste de corrección","La mayor implica ausencia o fallo sistémico de un requisito; la menor es un incumplimiento puntual","La mayor la detecta el auditor externo; la menor el interno","No existe tal distinción en ISO 27001"], c:1, e:"Una NC mayor implica que un requisito de la norma no se cumple de forma sistemática o no existe, poniendo en riesgo la integridad del SGSI. Una menor es un fallo puntual o aislado." },
    { q:"¿Qué es el 'riesgo residual' en el contexto de ISO 27001?", o:["El riesgo eliminado tras aplicar controles","El riesgo que permanece después de aplicar el tratamiento","El riesgo aceptado por la alta dirección sin análisis","El riesgo transferido a un tercero"], c:1, e:"El riesgo residual es el nivel de riesgo que queda una vez implementadas las medidas de tratamiento. Debe ser aceptado explícitamente por la dirección." },
    { q:"¿Qué nueva categoría de controles introduce ISO/IEC 27001:2022 respecto a 2013?", o:["Controles de nube","Controles preventivos","Controles de detección","Ninguna, los controles son los mismos"], c:0, e:"La versión 2022 añade controles específicos para servicios en la nube (como A.5.23), entre otras novedades como inteligencia de amenazas y continuidad TIC." },
    { q:"¿Qué significa que un control sea 'proporcional' al riesgo?", o:["Que su coste sea superior al impacto del riesgo","Que su nivel de protección sea adecuado al nivel de riesgo identificado","Que sea aplicado por igual a todos los activos","Que esté documentado en la SoA"], c:1, e:"Los controles deben ser proporcionales al nivel de riesgo: ni insuficientes (que dejen riesgo inaceptable) ni desproporcionados (coste mayor que el beneficio)." },
    { q:"¿Qué rol tiene el 'propietario del riesgo' en ISO 27001?", o:["Auditar los controles implementados","Ser responsable de la gestión y tratamiento de un riesgo específico","Aprobar el presupuesto del SGSI","Redactar la política de seguridad"], c:1, e:"El propietario del riesgo es la persona con autoridad y responsabilidad para gestionar un riesgo concreto, incluyendo decidir su tratamiento." },
    { q:"¿Qué es una 'oportunidad' en el contexto de la cláusula 6.1 de ISO 27001?", o:["Un riesgo con impacto positivo","Una posibilidad de mejorar el rendimiento del SGSI","Un control preventivo","Una amenaza mitigada"], c:1, e:"Las oportunidades son circunstancias favorables que pueden mejorar el SGSI, como nuevas tecnologías de seguridad o cambios normativos beneficiosos." },
    { q:"¿Qué documento establece los criterios para aceptar riesgos en ISO 27001?", o:["La SoA","El plan de tratamiento de riesgos","La metodología de evaluación de riesgos","El registro de activos"], c:2, e:"La metodología (o política) de gestión de riesgos debe definir los criterios de aceptación de riesgos antes de realizar la evaluación." },
    { q:"¿Con qué frecuencia mínima debe revisarse el SGSI por la dirección?", o:["Mensualmente","A intervalos planificados (mínimo anual en la práctica)","Cada 3 años coincidiendo con la renovación","Solo tras auditorías externas"], c:1, e:"La cláusula 9.3 exige revisiones por la dirección a intervalos planificados. En la práctica se realiza al menos anualmente para mantener la certificación." },
    { q:"¿Qué es el 'apetito de riesgo' en ISO 27001?", o:["El coste máximo aceptable de un incidente","La cantidad y tipo de riesgo que la organización está dispuesta a asumir","El número máximo de riesgos identificados","El umbral de activación del plan de continuidad"], c:1, e:"El apetito de riesgo define cuánto riesgo está dispuesta a tolerar la organización en la búsqueda de sus objetivos, estableciendo el umbral de aceptación." },
    { q:"¿Qué implica la cláusula 7.5 de ISO 27001 sobre información documentada?", o:["Eliminar documentación innecesaria","Controlar la creación, actualización y acceso a documentos del SGSI","Publicar toda la documentación externamente","Digitalizar todos los procesos"], c:1, e:"La cláusula 7.5 exige controlar la información documentada: su creación, formato, revisión, aprobación, distribución y protección." },
    { q:"¿Qué relación tiene ISO 27001 con el RGPD?", o:["ISO 27001 reemplaza al RGPD","La certificación ISO 27001 puede demostrar medidas técnicas adecuadas para el RGPD","Son normas incompatibles","El RGPD es un subconjunto de ISO 27001"], c:1, e:"ISO 27001 implementa controles técnicos y organizativos que pueden acreditar el cumplimiento del art. 32 del RGPD sobre seguridad del tratamiento." },
    { q:"¿Qué es una 'parte interesada' según ISO 27001 cláusula 4.2?", o:["Solo los clientes de la organización","Cualquier persona u organización que pueda afectar o verse afectada por el SGSI","Únicamente los empleados internos","Los auditores certificadores"], c:1, e:"Las partes interesadas (stakeholders) incluyen empleados, clientes, proveedores, reguladores y cualquier entidad con interés legítimo en el SGSI." },
    { q:"¿Qué opción de tratamiento implica contratar un seguro cibernético?", o:["Evitar el riesgo","Modificar el riesgo","Compartir el riesgo","Retener el riesgo"], c:2, e:"Contratar un seguro cibernético es una forma de compartir (transferir) el riesgo: se transfiere el impacto financiero a un tercero (la aseguradora)." },
    { q:"¿Qué es el Plan de Tratamiento de Riesgos (PTR)?", o:["El listado de todos los riesgos identificados","El documento que describe las acciones, responsables y plazos para tratar los riesgos","La política de gestión de incidentes","El registro de auditorías internas"], c:1, e:"El PTR detalla para cada riesgo: qué controles se implementan, quién es responsable, el coste estimado y el plazo de implementación." },
    { q:"¿Qué mide la 'eficacia' de un control en ISO 27001?", o:["Su coste de implementación","En qué medida reduce el riesgo al nivel deseado","El número de incidentes evitados","Su grado de documentación"], c:1, e:"La eficacia de un control mide si cumple su objetivo de reducir la probabilidad o el impacto del riesgo al nivel aceptable definido." },
    { q:"¿Qué cláusula de ISO 27001 aborda la competencia del personal del SGSI?", o:["Cláusula 5.3","Cláusula 7.2","Cláusula 8.1","Cláusula 9.2"], c:1, e:"La cláusula 7.2 (Competencia) exige determinar la competencia necesaria, asegurar que el personal es competente y conservar evidencia documentada." },
    { q:"¿Qué distingue a ISO 27001 de ISO 27002?", o:["27001 es de cumplimiento voluntario; 27002 es obligatoria","27001 es certificable con requisitos normativos; 27002 es una guía de buenas prácticas","27002 sustituye a 27001 en 2022","Son la misma norma con distinto nombre"], c:1, e:"ISO 27001 es la norma certificable con requisitos (SHALL). ISO 27002 es una guía de implementación de controles sin requisitos de certificación." },
    { q:"¿Qué es el 'contexto de la organización' en ISO 27001 cláusula 4.1?", o:["El sector industrial al que pertenece","Los factores internos y externos relevantes que afectan al SGSI","El tamaño de la empresa","El presupuesto de IT"], c:1, e:"El contexto incluye factores internos (cultura, estructura, tecnología) y externos (legales, regulatorios, mercado) que influyen en la capacidad del SGSI para lograr sus objetivos." },
    { q:"¿Cuál es el objetivo de la mejora continua en ISO 27001 (cláusula 10)?", o:["Reducir costes del SGSI","Aumentar la idoneidad, adecuación y eficacia del SGSI","Obtener nuevas certificaciones","Documentar todos los procesos"], c:1, e:"La cláusula 10 exige mejorar continuamente la idoneidad, adecuación y eficacia del SGSI, corrigiendo no conformidades y aplicando acciones correctivas." }
  ],

  // ══════════════════════════════════════════════════════════
  "ENS (Esquema Nacional de Seguridad)": [
    { q:"¿A qué entidades aplica el Esquema Nacional de Seguridad (ENS)?", o:["Solo a ministerios del Estado","Administraciones Públicas y sus proveedores TIC con sistemas que tratan datos públicos","Empresas privadas con más de 250 empleados","Únicamente a fuerzas y cuerpos de seguridad"], c:1, e:"El ENS (RD 311/2022) aplica a las AA.PP. españolas y a los proveedores privados que presten servicios o desarrollen sistemas para ellas." },
    { q:"¿Cuántas categorías de sistemas define el ENS?", o:["2 (básica y alta)","3 (básica, media y alta)","4 (mínima, básica, media y alta)","5 (de la 1 a la 5)"], c:1, e:"El ENS clasifica los sistemas en tres categorías: BÁSICA, MEDIA y ALTA, en función del impacto que tendría un incidente sobre la organización." },
    { q:"¿Qué dimensiones de seguridad evalúa el ENS para categorizar un sistema?", o:["Confidencialidad e integridad","Disponibilidad, autenticidad, trazabilidad, confidencialidad e integridad (DATCI)","CIA clásica","Solo disponibilidad y confidencialidad"], c:1, e:"El ENS utiliza 5 dimensiones: Disponibilidad, Autenticidad, Trazabilidad, Confidencialidad e Integridad (acrónimo DATCI)." },
    { q:"¿Qué real decreto regula actualmente el ENS en España?", o:["RD 3/2010","RD 951/2015","RD 311/2022","RD 1720/2007"], c:2, e:"El ENS vigente está regulado por el Real Decreto 311/2022, que derogó el RD 3/2010 y modernizó el esquema adaptándolo a NIS, RGPD y nuevas amenazas." },
    { q:"¿Qué es la 'Declaración de Conformidad' en el ENS para categoría BÁSICA?", o:["Un certificado emitido por el CCN","Una autoevaluación documentada firmada por el responsable de seguridad","Un informe de auditoría externa","Una acreditación de ENAC"], c:1, e:"Los sistemas de categoría BÁSICA pueden acreditar conformidad mediante autoevaluación, generando una Declaración de Conformidad sin necesidad de auditoría externa." },
    { q:"¿Cada cuánto tiempo deben auditarse los sistemas de categoría ALTA según el ENS?", o:["Cada 3 años","Cada 2 años","Anualmente","Solo tras incidentes graves"], c:1, e:"Los sistemas de categoría ALTA deben someterse a auditoría de seguridad cada 2 años, mientras que los de MEDIA cada 2 años también, pero con menor profundidad." },
    { q:"¿Qué organismo es el responsable del desarrollo y supervisión del ENS?", o:["INCIBE","AEPD","CCN (Centro Criptológico Nacional)","Ministerio de Hacienda"], c:2, e:"El CCN-CERT, dependiente del Centro Criptológico Nacional, es el organismo responsable de desarrollar las guías (series CCN-STIC) y supervisar el cumplimiento del ENS." },
    { q:"¿Qué son las guías CCN-STIC?", o:["Normativa de obligado cumplimiento con rango de ley","Documentos técnicos del CCN que orientan la implementación del ENS","Certificaciones de productos de seguridad","Informes anuales de ciberincidentes"], c:1, e:"Las guías CCN-STIC son documentos técnicos publicados por el CCN que proporcionan orientación práctica para implementar y auditar el ENS." },
    { q:"¿Qué papel juega el 'Responsable de Seguridad' en el ENS?", o:["Gestionar el presupuesto de TI","Determinar las decisiones de seguridad y supervisar su cumplimiento","Desarrollar las aplicaciones corporativas","Administrar los servidores"], c:1, e:"El Responsable de Seguridad es la figura que determina las decisiones en materia de seguridad, independiente del Responsable del Sistema para evitar conflictos de interés." },
    { q:"¿Qué medida de seguridad ENS cubre la gestión de incidentes?", o:["mp.s.1","op.exp.7","op.mon.3","mp.com.1"], c:1, e:"La medida op.exp.7 del ENS corresponde a la gestión de incidentes de seguridad, incluyendo detección, respuesta y notificación al CCN-CERT." },
    { q:"¿Qué significa 'proporcionalidad' en el ENS?", o:["Aplicar el mismo control a todos los sistemas","Adaptar las medidas de seguridad a la categoría y características de cada sistema","Gastar el mismo presupuesto en todos los departamentos","Copiar las medidas de otra Administración"], c:1, e:"El ENS exige que las medidas de seguridad sean proporcionales a la categoría del sistema y a los riesgos reales, evitando tanto el exceso como la insuficiencia." },
    { q:"¿Qué diferencia el ENS del RGPD en cuanto a su ámbito?", o:["El ENS protege datos personales; el RGPD protege sistemas","El ENS protege los sistemas de información públicos; el RGPD protege los datos personales","Son idénticos en ámbito y objetivo","El ENS solo aplica a defensa nacional"], c:1, e:"El ENS protege la seguridad de los sistemas de información de las AA.PP., mientras que el RGPD protege los derechos de los ciudadanos respecto a sus datos personales." },
    { q:"¿Qué es el 'perfil de cumplimiento específico' en el ENS 2022?", o:["Un anexo de la norma con controles adicionales","Una adecuación del ENS para colectivos concretos con requisitos simplificados","El nivel mínimo de controles para categoría básica","Un requisito solo para empresas privadas"], c:1, e:"Los perfiles de cumplimiento específicos son adaptaciones del ENS para colectivos concretos (p.ej. entidades locales pequeñas) que simplifican los requisitos manteniendo un nivel adecuado." },
    { q:"¿Cuál es el plazo máximo para notificar un incidente significativo al CCN-CERT según el ENS?", o:["72 horas","24 horas para incidentes críticos","Inmediatamente, sin plazo definido en la norma","7 días hábiles"], c:1, e:"Para incidentes de nivel crítico o muy alto, el ENS exige notificación al CCN-CERT en el menor plazo posible, en la práctica antes de 24 horas para los más graves." },
    { q:"¿Qué medida ENS regula el control de acceso lógico?", o:["op.acc.1 a op.acc.9","mp.if.1","op.exp.1","mp.s.2"], c:0, e:"Las medidas op.acc (de op.acc.1 a op.acc.9) regulan distintos aspectos del control de acceso: identificación, autenticación, gestión de privilegios, etc." },
    { q:"¿Qué es el INES en el contexto del ENS?", o:["Una herramienta de cifrado del CCN","El Informe Nacional del Estado de Seguridad, que agrega datos de cumplimiento ENS","Un sistema de gestión de incidentes","Una norma complementaria al ENS"], c:1, e:"INES (Informe Nacional del Estado de Seguridad) es el sistema del CCN que agrega y publica estadísticas anuales sobre el nivel de cumplimiento del ENS en las AA.PP." },
    { q:"¿Qué implica la medida de seguridad 'mp.per.3' del ENS?", o:["Concienciación del personal","Formación específica en seguridad","Comprobación de antecedentes del personal","Registro de actividad de usuarios"], c:0, e:"mp.per.3 corresponde a la concienciación del personal en materia de seguridad, exigiendo que todos los usuarios conozcan sus obligaciones." },
    { q:"¿Qué herramienta del CCN facilita el análisis de riesgos para el ENS?", o:["CLARA","PILAR","REYES","ARES"], c:1, e:"PILAR (Procedimiento Informático-Lógico para el Análisis de Riesgos) es la herramienta oficial del CCN para realizar análisis de riesgos alineados con el ENS y metodología MAGERIT." },
    { q:"¿Qué es MAGERIT en relación con el ENS?", o:["Una guía CCN-STIC","La metodología de análisis y gestión de riesgos de los sistemas de información de las AA.PP.","Un estándar europeo de certificación","Un catálogo de productos seguros"], c:1, e:"MAGERIT es la metodología de análisis y gestión de riesgos elaborada por el MAP (actual MPTFP) para las AA.PP. españolas, alineada con el ENS e ISO 31000." },
    { q:"¿Qué establece el ENS sobre el uso de productos de seguridad certificados?", o:["Prohíbe productos sin certificación Common Criteria","Recomienda el uso de productos con certificación de seguridad reconocida (CC, FIPS, etc.)","Exige exclusivamente productos nacionales","No menciona certificación de productos"], c:1, e:"El ENS recomienda el uso de productos con certificaciones de seguridad reconocidas (Common Criteria, FIPS 140) e incluye el catálogo de productos aprobados por el CCN." },
    { q:"¿Qué es el 'Responsable del Sistema' en el ENS?", o:["El CISO de la organización","La persona encargada del uso y explotación del sistema de información","El auditor interno","El DPO"], c:1, e:"El Responsable del Sistema es quien determina los requisitos del sistema en materia de seguridad y gestiona su operación diaria, diferenciándose del Responsable de Seguridad." },
    { q:"¿Qué medida ENS cubre las copias de seguridad?", o:["mp.si.3","op.exp.8","mp.com.3","op.acc.5"], c:0, e:"La medida mp.si.3 regula la copia de seguridad (backup) de los datos, estableciendo requisitos de frecuencia, integridad y pruebas de restauración." },
    { q:"¿Qué nivel de madurez mínimo exige el ENS para sistemas de categoría ALTA?", o:["Nivel 1 - Inicial","Nivel 3 - Definido","Nivel 2 - Gestionado","No define niveles de madurez"], c:1, e:"El ENS 2022 introduce niveles de madurez y los sistemas de categoría ALTA deben alcanzar un nivel 3 (procesos definidos y documentados) en las medidas críticas." },
    { q:"¿Qué implica la 'defensa en profundidad' como principio ENS?", o:["Cifrar todos los datos almacenados","Aplicar múltiples capas de seguridad de forma que el fallo de una no comprometa el sistema","Contratar múltiples proveedores de seguridad","Hacer copias de seguridad redundantes"], c:1, e:"La defensa en profundidad implica superponer capas de protección (red, sistema, aplicación, datos) de forma que un atacante deba superar múltiples controles." },
    { q:"¿Qué obligación tiene una AA.PP. cuando externaliza un servicio TIC bajo alcance ENS?", o:["Ninguna, la responsabilidad pasa al proveedor","Exigir al proveedor que cumpla el ENS en la parte que le corresponde","Solicitar certificación ISO 27001 al proveedor","Informar al CCN con 30 días de antelación"], c:1, e:"La AA.PP. debe trasladar contractualmente los requisitos ENS al proveedor y verificar su cumplimiento, ya que la responsabilidad ultima de conformidad sigue siendo de la Administración." },
    { q:"¿Qué es el catálogo de referencia de medidas de seguridad del ENS?", o:["El Anexo I del RD 311/2022","El Anexo II del RD 311/2022 con las medidas organizativas, operacionales y de protección","Las guías CCN-STIC 800","El INES"], c:1, e:"El Anexo II del RD 311/2022 contiene el catálogo de medidas de seguridad del ENS, organizadas en tres grupos: marco organizativo, operacional y medidas de protección." },
    { q:"¿Qué diferencia hay entre una medida ENS de aplicación 'R' y '[R]'?", o:["No hay diferencia","R es recomendada; [R] es requisito reforzado en categorías altas","R es obligatoria; [R] es opcional","R aplica en básica; [R] solo en alta"], c:1, e:"En el catálogo ENS, R indica medida recomendada y [R] indica que es recomendada pero con carácter reforzado o condicionado según la categoría del sistema." },
    { q:"¿Qué medida ENS regula la gestión de configuración de sistemas?", o:["op.exp.3","mp.si.1","op.acc.4","mp.per.1"], c:0, e:"op.exp.3 corresponde a la gestión de la configuración de seguridad, exigiendo configuraciones seguras (bastionado) y control de cambios documentado." },
    { q:"¿Qué novedad importante introduce el ENS 2022 respecto al de 2010?", o:["Elimina las categorías de sistemas","Incorpora requisitos específicos para cloud, IoT y teletrabajo","Reduce las dimensiones de seguridad a 3","Elimina la obligación de auditoría"], c:1, e:"El RD 311/2022 moderniza el ENS incorporando requisitos para entornos cloud, teletrabajo, cadena de suministro y nuevas amenazas, adaptándose a NIS2 y al marco europeo." },
    { q:"¿Qué es el sello 'ENS Certificado'?", o:["Una autoevaluación de cumplimiento","Una certificación emitida por entidad de certificación acreditada por ENAC que verifica la conformidad con el ENS","Un distintivo del CCN para sistemas auditados internamente","Una declaración voluntaria de las AA.PP."], c:1, e:"El sello ENS Certificado lo emiten entidades de certificación acreditadas por ENAC tras auditoría formal, acreditando la conformidad del sistema con el ENS en la categoría correspondiente." }
  ],

  // ══════════════════════════════════════════════════════════
  "NIS2 Directive": [
    { q:"¿Cuándo entró en vigor la obligación de transposición de NIS2 en los Estados Miembro?", o:["Enero 2023","Octubre 2024","Enero 2025","Mayo 2023"], c:1, e:"La Directiva NIS2 (2022/2555) debía ser transpuesta por los Estados Miembro antes del 17 de octubre de 2024." },
    { q:"¿Qué diferencia principal existe entre NIS1 y NIS2 en cuanto al ámbito de aplicación?", o:["NIS2 solo aplica a sector financiero","NIS2 amplía significativamente los sectores cubiertos y el número de entidades obligadas","NIS2 reduce el ámbito a infraestructuras críticas","Son equivalentes en alcance"], c:1, e:"NIS2 amplía el ámbito respecto a NIS1: incorpora más sectores (administración pública, espacio, aguas residuales, manufactura crítica) y elimina la discrecionalidad de los Estados para identificar operadores." },
    { q:"¿Qué dos categorías de entidades distingue NIS2?", o:["Críticas y sensibles","Esenciales e importantes","Primarias y secundarias","Reguladas y voluntarias"], c:1, e:"NIS2 clasifica las entidades en 'esenciales' (sectores de alta criticidad como energía, transporte, banca) e 'importantes' (otros sectores críticos como servicios postales, gestión de residuos)." },
    { q:"¿En cuánto tiempo debe notificarse un incidente significativo a la autoridad competente según NIS2?", o:["72 horas para alerta temprana; 1 mes para informe final","24 horas para alerta temprana; 72 horas para notificación; 1 mes para informe final","48 horas para notificación completa","7 días hábiles"], c:1, e:"NIS2 establece un proceso escalonado: alerta temprana en 24h, notificación completa en 72h y informe final en 1 mes, con posibilidad de informe intermedio." },
    { q:"¿Qué responsabilidad personal establece NIS2 para los órganos de dirección?", o:["Ninguna, la responsabilidad recae en el CISO","Pueden ser declarados personalmente responsables por incumplimientos graves","Solo responsabilidad moral","Responsabilidad civil limitada al salario anual"], c:1, e:"NIS2 introduce responsabilidad personal para directivos: los órganos de dirección pueden ser sancionados personalmente, incluyendo inhabilitación temporal para el ejercicio directivo." },
    { q:"¿Cuál es la sanción máxima para entidades esenciales bajo NIS2?", o:["1 millón de euros","10 millones de euros o el 2% de la facturación mundial anual (el mayor)","5 millones de euros","El 4% de la facturación global"], c:1, e:"Las entidades esenciales pueden ser sancionadas con hasta 10 millones de euros o el 2% de su facturación anual mundial, aplicándose el importe más elevado." },
    { q:"¿Qué medidas de seguridad exige NIS2 a las entidades obligadas?", o:["Solo medidas técnicas de cifrado","Un enfoque de gestión de riesgos que incluya políticas, gestión de incidentes, continuidad, cadena de suministro y criptografía","Únicamente planes de continuidad de negocio","Certificación ISO 27001 obligatoria"], c:1, e:"NIS2 exige medidas proporcionales al riesgo: políticas de seguridad, gestión de incidentes, continuidad, seguridad de la cadena de suministro, criptografía y control de acceso, entre otras." },
    { q:"¿Qué es ENISA en el contexto de NIS2?", o:["La autoridad nacional de ciberseguridad española","La Agencia de la UE para la Ciberseguridad, con rol reforzado en NIS2","El organismo que emite certificaciones NIS2","Un CERT europeo"], c:1, e:"ENISA (Agencia de la UE para la Ciberseguridad) tiene un papel reforzado en NIS2: apoya a los Estados Miembro, emite directrices y coordina respuesta a crisis cibernéticas." },
    { q:"¿Qué es la 'seguridad de la cadena de suministro' en NIS2?", o:["Asegurar el transporte físico de mercancías","Gestionar los riesgos de ciberseguridad derivados de proveedores y prestadores de servicios TIC","Certificar a todos los proveedores con ISO 27001","Auditar los data centers de terceros"], c:1, e:"NIS2 obliga a las entidades a evaluar y gestionar los riesgos de ciberseguridad de su cadena de suministro, incluyendo acuerdos contractuales con proveedores críticos." },
    { q:"¿Qué umbral de tamaño determina la aplicación de NIS2 con carácter general?", o:["Empresas con más de 500 empleados","Medianas (>50 empleados o >10M€ facturación) y grandes empresas","Solo grandes empresas (>250 empleados)","Toda empresa con presencia digital"], c:1, e:"NIS2 aplica con carácter general a empresas medianas (>50 empleados O >10M€ facturación) y grandes, aunque ciertos sectores críticos están incluidos independientemente del tamaño." },
    { q:"¿Qué obligación de formación establece NIS2 para los órganos de dirección?", o:["Obtener certificación CISM","Recibir formación periódica en ciberseguridad y promoverla para empleados","Contratar un CISO certificado","Superar un examen anual de ciberseguridad"], c:1, e:"NIS2 exige que los miembros del órgano de dirección reciban formación periódica en ciberseguridad y fomenten la formación continua de los empleados." },
    { q:"¿Qué es el registro de entidades obligadas bajo NIS2?", o:["Un directorio público de todas las empresas certificadas","El proceso por el que las entidades deben identificarse ante su autoridad nacional competente","Un ranking de ciberseguridad europeo","Una base de datos de incidentes"], c:1, e:"NIS2 obliga a las entidades a registrarse ante la autoridad competente nacional, proporcionando información básica sobre su actividad, tamaño y contactos de seguridad." },
    { q:"¿Cómo aborda NIS2 la divulgación coordinada de vulnerabilidades?", o:["La prohíbe para proteger a los fabricantes","La promueve estableciendo marcos nacionales de CVD y el papel de ENISA","La delega exclusivamente al sector privado","No la menciona"], c:1, e:"NIS2 promueve la divulgación coordinada de vulnerabilidades (CVD), exigiendo a los Estados Miembro designar coordinadores nacionales y apoyando la base de datos europea de vulnerabilidades." },
    { q:"¿Qué red de cooperación refuerza NIS2 entre los Estados Miembro?", o:["FIRST","CyCLONe y la red de CSIRTs","INTERPOL Cyber","EU-CERT"], c:1, e:"NIS2 refuerza CyCLONe (Cyber Crisis Liaison Organisation Network) para gestión de crisis cibernéticas a gran escala y la red de CSIRTs para cooperación operativa." },
    { q:"¿Qué sectores de 'alta criticidad' identifica el Anexo I de NIS2?", o:["Solo energía y transporte","Energía, transporte, banca, infraestructuras de mercados financieros, sanidad, agua, digital e infraestructuras TIC","Solo infraestructuras digitales","Defensa y seguridad nacional"], c:1, e:"El Anexo I de NIS2 lista 11 sectores de alta criticidad: energía, transporte, banca, mercados financieros, sanidad, agua potable, aguas residuales, infraestructura digital, gestión de servicios TIC, administración pública y espacio." },
    { q:"¿Qué diferencia hay entre las sanciones para entidades esenciales e importantes en NIS2?", o:["No hay diferencia","Esenciales: hasta 10M€ o 2% facturación; Importantes: hasta 7M€ o 1,4% facturación","Esenciales: hasta 20M€; Importantes: hasta 10M€","Solo las esenciales son sancionables"], c:1, e:"NIS2 establece sanciones diferenciadas: entidades esenciales hasta 10M€ o 2% facturación global; entidades importantes hasta 7M€ o 1,4% facturación global." },
    { q:"¿Qué es el esquema europeo de certificación de ciberseguridad en el contexto NIS2/ENISA?", o:["Una norma obligatoria para todos los productos TIC","Marcos voluntarios (o con elementos obligatorios) de certificación de productos, servicios y procesos TIC bajo el Cybersecurity Act","Una directiva paralela a NIS2","Una certificación personal de profesionales"], c:1, e:"El Cybersecurity Act (2019) complementa a NIS2 creando el marco europeo de certificación de ciberseguridad (EUCC), con esquemas por niveles (básico, sustancial, elevado)." },
    { q:"¿Qué obliga NIS2 respecto al uso de criptografía?", o:["Uso obligatorio de algoritmos aprobados por ENISA","Implementar cifrado de extremo a extremo donde sea apropiado como parte de las medidas de gestión de riesgos","Prohibir el cifrado de extremo a extremo","Solo cifrar datos en tránsito"], c:1, e:"NIS2 exige el uso de criptografía y cifrado donde sea apropiado como parte de las medidas de seguridad, sin imponer algoritmos específicos." },
    { q:"¿Qué plazo tienen los Estados Miembro para transponer NIS2 a su legislación nacional?", o:["6 meses desde su publicación","17 de octubre de 2024","31 de diciembre de 2024","Enero de 2026"], c:1, e:"El plazo de transposición de NIS2 era el 17 de octubre de 2024. Varios Estados Miembro, incluida España, iniciaron el proceso con retraso." },
    { q:"¿Qué rol tienen los proveedores de servicios gestionados (MSP) bajo NIS2?", o:["Están excluidos del ámbito de NIS2","Pueden ser entidades obligadas y son considerados parte crítica de la cadena de suministro","Solo deben cumplir NIS2 si tienen más de 500 empleados","No tienen obligaciones específicas"], c:1, e:"Los MSP y MSSP están expresamente incluidos en NIS2 como entidades obligadas (sector de gestión de servicios TIC) y son considerados riesgo clave de cadena de suministro." },
    { q:"¿Qué es un 'incidente significativo' según NIS2?", o:["Cualquier alerta de seguridad","Incidente que ha causado o puede causar perturbaciones operativas graves o pérdidas económicas o sociales significativas","Solo incidentes con datos personales comprometidos","Incidentes que afecten a más de 1000 usuarios"], c:1, e:"NIS2 define incidente significativo como aquel que causa perturbación operativa grave del servicio, pérdidas financieras o impacto en otras personas físicas o jurídicas." },
    { q:"¿Qué mecanismo de supervisión establece NIS2 para entidades esenciales?", o:["Supervisión reactiva (solo tras incidente)","Supervisión proactiva ex-ante, incluyendo auditorías, inspecciones y escaneos de seguridad","Solo autoevaluación anual","Certificación obligatoria cada 2 años"], c:1, e:"Para entidades esenciales, NIS2 establece supervisión proactiva ex-ante: autoridades pueden realizar auditorías, inspecciones in situ, escaneos de seguridad y solicitar información sin esperar a un incidente." },
    { q:"¿Qué exige NIS2 sobre las políticas de seguridad para recursos humanos?", o:["Nada específico sobre RRHH","Políticas de seguridad en el ciclo de vida del empleado, incluyendo incorporación, cambio de rol y baja","Solo formación inicial de nuevos empleados","Verificación de antecedentes para todos los empleados"], c:1, e:"NIS2 exige políticas de seguridad que cubran el ciclo de vida del empleado: verificación de antecedentes, formación, gestión de accesos y procedimientos de baja o cambio de función." },
    { q:"¿Cómo relaciona NIS2 con el RGPD en caso de incidente con datos personales?", o:["NIS2 reemplaza al RGPD en estos casos","Son obligaciones complementarias: NIS2 exige notificar a la autoridad NIS; el RGPD exige notificar a la AEPD en 72h si hay datos personales","NIS2 tiene prevalencia sobre el RGPD","Solo aplica el RGPD"], c:1, e:"NIS2 y RGPD son complementarios: un incidente con datos personales puede requerir notificación simultánea bajo NIS2 (a la autoridad NIS) y bajo RGPD (a la autoridad de protección de datos)." },
    { q:"¿Qué obligación establece NIS2 sobre los puntos de contacto únicos?", o:["Cada empresa debe designar un punto de contacto público","Cada Estado Miembro debe designar un punto de contacto único nacional para cooperación transfronteriza","Los puntos de contacto son voluntarios","Solo aplica a entidades esenciales transnacionales"], c:1, e:"NIS2 exige que cada Estado Miembro designe un punto de contacto único (single point of contact) para facilitar la cooperación transfronteriza en ciberseguridad." },
    { q:"¿Qué es el 'enfoque multirriesgo' que exige NIS2?", o:["Evaluar únicamente riesgos cibernéticos","Considerar todos los riesgos relevantes: cibernéticos, físicos, de cadena de suministro y de continuidad de forma integrada","Separar los riesgos TI de los OT","Centrase solo en amenazas externas"], c:1, e:"NIS2 exige un enfoque 'all-hazards' o multirriesgo: las entidades deben considerar y gestionar de forma integrada todos los riesgos que puedan afectar a la seguridad de sus redes y sistemas." },
    { q:"¿Qué diferencia NIS2 de la Directiva CER (resiliencia de entidades críticas)?", o:["Son la misma directiva","NIS2 cubre seguridad de redes y sistemas; CER cubre resiliencia física de infraestructuras críticas","CER reemplaza a NIS2 para infraestructuras críticas","Solo NIS2 tiene carácter obligatorio"], c:1, e:"NIS2 y CER son complementarias: NIS2 aborda la ciberseguridad de redes y sistemas de información; la Directiva CER (2022/2557) cubre la resiliencia física de entidades críticas." },
    { q:"¿Qué implica para España la no transposición en plazo de NIS2?", o:["Ninguna consecuencia inmediata","Posible procedimiento de infracción de la Comisión Europea y aplicación directa de ciertos principios","Multa automática de 10M€","Suspensión de fondos europeos"], c:1, e:"El incumplimiento del plazo de transposición puede conllevar un procedimiento de infracción ante el TJUE y la posible responsabilidad del Estado. Además, ciertos principios de NIS2 pueden ser de aplicación directa." },
    { q:"¿Qué sectores adicionales cubre el Anexo II de NIS2 (sectores importantes)?", o:["Defensa y seguridad nacional","Servicios postales, gestión de residuos, fabricación crítica, productos químicos, alimentación e investigación","Solo servicios digitales adicionales","Telecomunicaciones exclusivamente"], c:1, e:"El Anexo II de NIS2 incluye sectores importantes adicionales: servicios postales y de mensajería, gestión de residuos, fabricación de productos críticos, químicos, alimentación e investigación." },
    { q:"¿Qué herramienta promueve NIS2 para el intercambio de información entre entidades?", o:["Correo electrónico cifrado obligatorio","Acuerdos voluntarios de intercambio de información (ISACs) entre sectores","Una plataforma centralizada gestionada por ENISA","Informes trimestrales obligatorios entre competidores"], c:1, e:"NIS2 promueve los ISACs (Information Sharing and Analysis Centers) como mecanismo voluntario para el intercambio de información sobre amenazas, vulnerabilidades e incidentes entre entidades del mismo sector." }
  ],

  // ══════════════════════════════════════════════════════════
  "RGPD / GDPR": [
    { q:"¿Cuándo entró en aplicación el RGPD?", o:["25 de mayo de 2016","25 de mayo de 2018","1 de enero de 2019","25 de mayo de 2017"], c:1, e:"El RGPD (Reglamento 2016/679) se publicó en mayo de 2016 pero fue de aplicación obligatoria a partir del 25 de mayo de 2018, tras un período de adaptación de 2 años." },
    { q:"¿Qué es el 'principio de minimización de datos' en el RGPD?", o:["Almacenar el mínimo tiempo posible","Recoger solo los datos adecuados, pertinentes y limitados a lo necesario para la finalidad","Minimizar el número de responsables del tratamiento","Reducir el presupuesto de protección de datos"], c:1, e:"El principio de minimización (art. 5.1.c) exige que los datos personales sean adecuados, pertinentes y limitados a lo necesario en relación con los fines del tratamiento." },
    { q:"¿Qué plazo tiene el responsable para notificar una brecha de datos a la autoridad supervisora?", o:["24 horas","72 horas desde que tiene conocimiento","7 días hábiles","30 días naturales"], c:1, e:"El art. 33 RGPD exige notificar las brechas de seguridad a la autoridad de control (AEPD en España) en el plazo máximo de 72 horas desde que se tiene conocimiento." },
    { q:"¿Qué es una Evaluación de Impacto en la Protección de Datos (EIPD/DPIA)?", o:["Una auditoría anual obligatoria para todas las empresas","Un análisis previo obligatorio cuando un tratamiento puede suponer alto riesgo para los derechos de los interesados","Un informe de incidentes de seguridad","La valoración económica de los datos personales"], c:1, e:"La DPIA (art. 35) es obligatoria cuando un tipo de tratamiento entraña alto riesgo para los derechos y libertades. Debe realizarse antes de iniciar el tratamiento." },
    { q:"¿Cuándo es obligatorio designar un Delegado de Protección de Datos (DPD/DPO)?", o:["En todas las empresas con más de 50 empleados","En organismos públicos, empresas que tratan datos a gran escala o categorías especiales, y las que realizan monitorización sistemática a gran escala","Solo en empresas del sector sanitario","En toda empresa con más de 250 empleados"], c:1, e:"El art. 37 RGPD establece la obligatoriedad del DPO para: organismos públicos, responsables que traten datos a gran escala o categorías especiales, y quienes realicen monitorización sistemática a gran escala." },
    { q:"¿Qué base jurídica NO está reconocida en el art. 6 del RGPD?", o:["Consentimiento","Contrato","Pago económico al interesado","Interés legítimo"], c:2, e:"Las bases jurídicas del art. 6 son: consentimiento, contrato, obligación legal, intereses vitales, misión de interés público e interés legítimo. El pago económico no es una base jurídica reconocida." },
    { q:"¿Qué derecho permite al interesado oponerse al tratamiento de sus datos con fines de marketing directo?", o:["Derecho de acceso","Derecho de oposición (art. 21)","Derecho de supresión","Derecho de rectificación"], c:1, e:"El art. 21 reconoce el derecho de oposición, que debe atenderse siempre cuando el tratamiento sea para marketing directo, sin necesidad de alegar causa alguna." },
    { q:"¿Qué es la 'portabilidad de datos' según el RGPD?", o:["El derecho a eliminar todos los datos","El derecho a recibir los datos personales en formato estructurado y transmitirlos a otro responsable","El derecho a corregir datos incorrectos","El derecho a limitar el tratamiento"], c:1, e:"El art. 20 RGPD reconoce el derecho a recibir los datos en formato estructurado, de uso común y lectura mecánica, y a transmitirlos a otro responsable cuando el tratamiento se base en consentimiento o contrato." },
    { q:"¿Cuál es la sanción máxima del RGPD para infracciones más graves?", o:["1 millón de euros","20 millones de euros o el 4% de la facturación anual global (el mayor)","10 millones de euros","El 2% de la facturación global"], c:1, e:"Las infracciones más graves (art. 83.5) pueden sancionarse con hasta 20 millones de euros o el 4% del volumen de negocio anual global, aplicándose el importe más elevado." },
    { q:"¿Qué principio del RGPD exige que los datos no se conserven más tiempo del necesario?", o:["Minimización","Limitación del plazo de conservación","Exactitud","Integridad y confidencialidad"], c:1, e:"El principio de limitación del plazo de conservación (art. 5.1.e) exige que los datos se mantengan solo durante el tiempo necesario para cumplir la finalidad del tratamiento." },
    { q:"¿Qué es el 'Privacy by Design' según el RGPD?", o:["Diseñar interfaces de usuario amigables","Incorporar la protección de datos desde el diseño del sistema o proceso, no como añadido posterior","Un sello de privacidad europeo","La política de privacidad visible en la web"], c:1, e:"El art. 25 RGPD exige Privacy by Design: integrar la protección de datos desde el diseño del tratamiento y por defecto, aplicando principios de minimización y protección desde el inicio." },
    { q:"¿Qué información mínima debe contener un Registro de Actividades de Tratamiento (RAT)?", o:["Solo el nombre del responsable y la finalidad","Nombre del responsable, finalidades, categorías de interesados y datos, destinatarios, transferencias internacionales y plazos de supresión","Solo las transferencias internacionales","El consentimiento de cada interesado"], c:1, e:"El RAT (art. 30) debe incluir: nombre del responsable, finalidades, categorías de interesados y datos, destinatarios, transferencias internacionales, plazos de conservación y medidas de seguridad." },
    { q:"¿Qué significa que un tercero sea 'encargado del tratamiento' según el RGPD?", o:["Una empresa que compra datos personales","Una entidad que trata datos por cuenta del responsable del tratamiento","Un subcontratista que no accede a datos personales","El DPO de la organización"], c:1, e:"El encargado del tratamiento (art. 4.8) es quien trata datos personales por cuenta del responsable. Debe existir un contrato (DPA) que regule ese tratamiento conforme al art. 28 RGPD." },
    { q:"¿Cuándo puede realizarse una transferencia internacional de datos fuera del EEE?", o:["Siempre que el receptor firme un documento de aceptación","Cuando existe decisión de adecuación, garantías apropiadas (SCCs, BCRs) o excepciones específicas","Solo hacia países anglófonos","Con el simple consentimiento del interesado siempre"], c:1, e:"Las transferencias internacionales (cap. V) requieren: decisión de adecuación de la Comisión, garantías apropiadas (cláusulas contractuales tipo, normas corporativas vinculantes) o una de las excepciones del art. 49." },
    { q:"¿Qué es el 'derecho al olvido' en el RGPD?", o:["El derecho a que los buscadores olviden tu nombre","El derecho de supresión: solicitar que se eliminen los datos cuando ya no son necesarios o se retira el consentimiento","El derecho a corregir información errónea","El derecho a no ser perfilado"], c:1, e:"El derecho de supresión o 'al olvido' (art. 17) permite solicitar la eliminación de datos cuando ya no son necesarios, se retira el consentimiento, se ejerce oposición o el tratamiento es ilícito." },
    { q:"¿Qué son las 'categorías especiales de datos' en el RGPD?", o:["Datos de menores de 14 años","Datos que revelan origen racial, político, religioso, genético, biométrico, salud, vida sexual o afiliación sindical","Datos financieros y bancarios","Datos de localización GPS"], c:1, e:"El art. 9 RGPD define categorías especiales: datos que revelan origen racial/étnico, opiniones políticas, creencias religiosas, datos genéticos, biométricos, salud, vida/orientación sexual y afiliación sindical." },
    { q:"¿Qué mecanismo permite a un grupo empresarial multinacional gestionar sus transferencias internas de datos?", o:["Cláusulas contractuales tipo (SCCs)","Normas Corporativas Vinculantes (BCRs/Binding Corporate Rules)","Escudo de privacidad","Acuerdo de confidencialidad interno"], c:1, e:"Las BCRs (art. 47) son políticas internas de protección de datos aprobadas por la autoridad de control, que permiten transferencias legítimas dentro de un grupo empresarial multinacional." },
    { q:"¿Qué principio exige que los datos personales sean exactos y se actualicen cuando sea necesario?", o:["Minimización","Exactitud (art. 5.1.d)","Limitación de la finalidad","Licitud"], c:1, e:"El principio de exactitud (art. 5.1.d) exige que los datos sean exactos y, si es necesario, actualizados, tomando medidas razonables para suprimir o rectificar datos inexactos." },
    { q:"¿Qué es el 'interés legítimo' como base jurídica del RGPD?", o:["Un interés económico de la empresa","Un interés del responsable o tercero que prevalece sobre los derechos del interesado tras ponderación","El interés del Estado en el tratamiento","Una base jurídica solo disponible para organismos públicos"], c:1, e:"El interés legítimo (art. 6.1.f) permite el tratamiento cuando es necesario para un interés legítimo del responsable o tercero, siempre que no prevalezcan los derechos del interesado (test de ponderación)." },
    { q:"¿Qué obligación tiene el responsable cuando una brecha afecta a los derechos de los interesados?", o:["Solo notificar a la AEPD","Notificar a la AEPD (art. 33) Y comunicar a los interesados afectados sin dilación indebida (art. 34)","Publicar la brecha en su web","Solo comunicar a los interesados si hay más de 1000 afectados"], c:1, e:"Cuando una brecha entraña alto riesgo para los interesados, el responsable debe notificar a la autoridad (art. 33) Y comunicar directamente a los afectados (art. 34) para que puedan tomar medidas." },
    { q:"¿Qué edad mínima exige el RGPD para el consentimiento digital de menores (con carácter general)?", o:["13 años","16 años (con posibilidad de que los Estados bajen hasta 13)","18 años","14 años en todos los casos"], c:1, e:"El RGPD establece 16 años como edad general para el consentimiento digital de menores, pero permite a los Estados Miembro reducirla hasta 13 años. España fijó 14 años en la LOPDGDD." },
    { q:"¿Qué es la 'profilación' y cómo la regula el RGPD?", o:["Está prohibida en todo caso","Es el tratamiento automatizado para evaluar aspectos personales; el interesado tiene derecho a no ser objeto de decisiones basadas únicamente en ella","Es obligatoria para el marketing digital","Solo está regulada para datos financieros"], c:1, e:"La profilación (art. 4.4) es el tratamiento automatizado para evaluar aspectos de una persona. El art. 22 reconoce el derecho a no ser objeto de decisiones basadas únicamente en tratamiento automatizado con efectos significativos." },
    { q:"¿Qué es el principio de 'responsabilidad proactiva' (accountability) en el RGPD?", o:["Responder rápidamente a las solicitudes de los interesados","El responsable debe aplicar medidas técnicas y organizativas y ser capaz de demostrar su cumplimiento","Publicar todos los tratamientos en el BOE","Contratar un seguro de responsabilidad civil"], c:1, e:"El principio de accountability (art. 5.2) exige que el responsable no solo cumpla el RGPD sino que pueda demostrar ese cumplimiento mediante evidencias documentadas." },
    { q:"¿Qué garantías específicas exige el RGPD para el tratamiento de datos de menores?", o:["Ninguna específica, aplican las reglas generales","Lenguaje claro y comprensible en la información, consentimiento parental para menores de 16 (o la edad fijada) y DPIA cuando se traten a gran escala","Prohibición absoluta de tratar datos de menores","Solo almacenarlos cifrados"], c:1, e:"El RGPD exige información comprensible para menores, verificación del consentimiento parental según la edad fijada por cada Estado, y recomienda DPIA cuando se tratan datos de menores a gran escala." },
    { q:"¿Qué implica el principio de 'limitación de la finalidad' en el RGPD?", o:["Los datos solo pueden usarse para una única finalidad en toda la vida del tratamiento","Los datos deben recogerse con fines determinados, explícitos y legítimos, y no tratarse de forma incompatible con esos fines","Los datos deben eliminarse cuando se cumple la finalidad en todos los casos","La finalidad puede ampliarse con solo actualizar la política de privacidad"], c:1, e:"El principio de limitación de la finalidad (art. 5.1.b) exige que los datos se recojan para fines específicos y no se traten de forma incompatible con ellos, aunque sí pueden usarse para fines compatibles o con nueva base jurídica." },
    { q:"¿Qué es el Marco de Privacidad de Datos UE-EEUU (EU-US Data Privacy Framework)?", o:["Un acuerdo bilateral que sustituye definitivamente a las SCCs","El mecanismo actual (desde julio 2023) que permite transferencias UE-EEUU para empresas certificadas, sustituyendo al Privacy Shield","Una norma del RGPD sobre transferencias","Un acuerdo de cooperación judicial"], c:1, e:"El EU-US Data Privacy Framework, adoptado en julio 2023, es el mecanismo actual para transferencias UE-EEUU, basado en la certificación de empresas estadounidenses y supervisado por el DoC y la FTC." },
    { q:"¿Cuándo puede el responsable denegar el ejercicio del derecho de acceso?", o:["Siempre que sea costoso atenderlo","En casos tasados: solicitudes manifiestamente infundadas o excesivas, o cuando afecte a derechos de terceros o secreto de empresa","Cuando el interesado no aporte documento de identidad original","Solo si hay resolución judicial"], c:1, e:"El art. 12.5 permite denegar o cobrar tasa por solicitudes manifiestamente infundadas o excesivas (por su carácter repetitivo). También pueden limitarse derechos para proteger derechos de terceros o investigaciones." },
    { q:"¿Qué es la LOPDGDD en relación con el RGPD?", o:["Una norma que reemplaza al RGPD en España","La Ley Orgánica de Protección de Datos y Garantía de Derechos Digitales, que adapta y complementa el RGPD en España","Una guía de cumplimiento de la AEPD","El reglamento de desarrollo del RGPD"], c:1, e:"La LOPDGDD (LO 3/2018) adapta el RGPD al ordenamiento español, ejerciendo las opciones que el Reglamento deja a los Estados Miembro, e incorpora un catálogo de derechos digitales." },
    { q:"¿Qué medidas técnicas mínimas exige el RGPD para proteger datos personales?", o:["Cifrado AES-256 obligatorio y 2FA","Medidas apropiadas al riesgo: pseudonimización, cifrado, garantías de confidencialidad, integridad, disponibilidad y resiliencia","Almacenamiento exclusivo en servidores de la UE","Auditoría anual obligatoria de terceros"], c:1, e:"El art. 32 RGPD no prescribe medidas específicas sino que exige medidas técnicas y organizativas apropiadas al riesgo: pseudonimización, cifrado, capacidad de garantizar confidencialidad, integridad, disponibilidad y resiliencia." },
    { q:"¿Qué es el 'consentimiento explícito' en el RGPD y cuándo es necesario?", o:["El consentimiento por escrito en papel","Una manifestación inequívoca mediante acto afirmativo claro; es necesario para categorías especiales y algunas transferencias internacionales","El doble opt-in en email marketing","Cualquier tipo de consentimiento bajo el RGPD"], c:1, e:"El consentimiento explícito (art. 9.2.a) es especialmente exigente: requiere una declaración verbal o escrita expresa. Es necesario para tratar categorías especiales de datos y en algunas excepciones de transferencias internacionales." }
  ],

  // ══════════════════════════════════════════════════════════
  "ISO 22301 BCM": [
    { q:"¿Cuál es el objeto de ISO 22301?", o:["Gestión de la seguridad de la información","Sistema de Gestión de Continuidad de Negocio (SGCN)","Gestión de riesgos operacionales","Auditoría de sistemas de información"], c:1, e:"ISO 22301 especifica los requisitos para implementar, mantener y mejorar un Sistema de Gestión de Continuidad de Negocio (SGCN/BCMS), protegiendo a las organizaciones frente a interrupciones." },
    { q:"¿Qué es el BIA (Business Impact Analysis) en ISO 22301?", o:["Un análisis de riesgos de seguridad","El análisis que identifica el impacto de interrupciones en las actividades críticas y determina los tiempos de recuperación tolerables","Un inventario de activos de negocio","El presupuesto de continuidad"], c:1, e:"El BIA es el proceso que identifica las actividades críticas, analiza el impacto de su interrupción (financiero, reputacional, legal) y determina parámetros como RTO y RPO." },
    { q:"¿Qué significa RTO?", o:["Recovery Time Objective: el tiempo máximo tolerable para restaurar una actividad","Real Time Operations: operaciones en tiempo real","Recovery Transfer Operation: transferencia de operaciones","Response Time Output: tiempo de respuesta del sistema"], c:0, e:"El RTO (Recovery Time Objective) es el tiempo máximo que una actividad puede estar interrumpida antes de que las consecuencias sean inaceptables para la organización." },
    { q:"¿Qué significa RPO en continuidad de negocio?", o:["Recovery Point Objective: el punto en el tiempo al que deben restaurarse los datos tras una interrupción","Recovery Process Operation","Real Point of Operations","Response Plan Output"], c:0, e:"El RPO (Recovery Point Objective) define la antigüedad máxima de los datos que deben recuperarse tras un incidente, es decir, cuánta pérdida de datos es tolerable." },
    { q:"¿Qué es el MTPD en ISO 22301?", o:["Maximum Tolerable Period of Disruption: tiempo máximo que puede durar una interrupción antes de comprometer la supervivencia","Minimum Time for Process Deployment","Maximum Transfer Point for Data","Método de Triage y Priorización de Daños"], c:0, e:"El MTPD (Maximum Tolerable Period of Disruption) es el tiempo máximo que una organización puede tolerar una interrupción antes de que las consecuencias sean irreversibles para su supervivencia." },
    { q:"¿Qué documento es el núcleo operativo de la continuidad en ISO 22301?", o:["La política de continuidad","El Plan de Continuidad de Negocio (BCP)","El registro de activos críticos","El informe de auditoría interna"], c:1, e:"El BCP (Business Continuity Plan) es el documento operativo que describe cómo la organización responderá y recuperará sus actividades críticas ante una interrupción." },
    { q:"¿Cuál es la diferencia entre el Plan de Continuidad (BCP) y el Plan de Recuperación ante Desastres (DRP)?", o:["Son sinónimos","El BCP cubre la continuidad de actividades de negocio; el DRP se centra en la recuperación de infraestructura TI","El DRP es más amplio que el BCP","El BCP solo aplica a desastres naturales"], c:1, e:"El BCP abarca todas las actividades críticas de negocio (personas, procesos, instalaciones, tecnología). El DRP es un subconjunto enfocado en la recuperación de sistemas TI y datos." },
    { q:"¿Con qué frecuencia mínima deben ejercitarse los planes de continuidad según ISO 22301?", o:["Cada 5 años","A intervalos planificados; en la práctica mínimo anual para los planes críticos","Solo tras una activación real","Cada 3 años coincidiendo con la auditoría de certificación"], c:1, e:"ISO 22301 exige ejercicios y pruebas a intervalos planificados. En la práctica, los planes críticos deben ejercitarse al menos anualmente para garantizar su eficacia." },
    { q:"¿Qué es una 'estrategia de continuidad' en ISO 22301?", o:["El presupuesto asignado a continuidad","El enfoque seleccionado para recuperar y continuar una actividad ante una interrupción (ej: sitio alternativo, trabajo remoto, acuerdo con terceros)","La política de seguridad de la información","El proceso de notificación de incidentes"], c:1, e:"Las estrategias de continuidad son los enfoques seleccionados para recuperar actividades críticas: sitio alternativo, teletrabajo, subcontratación, acuerdos de reciprocidad, etc." },
    { q:"¿Qué relación tiene ISO 22301 con ISO 27001?", o:["Son normas incompatibles","Son complementarias: 27001 protege la información; 22301 asegura que el negocio continúa ante interrupciones","22301 reemplaza a 27001 para continuidad TI","Son la misma norma con distinto nombre"], c:1, e:"ISO 27001 y 22301 son complementarias y muchas organizaciones las implementan juntas: 27001 gestiona la seguridad de la información; 22301 asegura la continuidad de las operaciones ante interrupciones graves." },
    { q:"¿Qué es el 'mínimo viable de negocio' en continuidad?", o:["El presupuesto mínimo de operaciones","El nivel mínimo de recursos y capacidades necesarios para operar en modo de contingencia","El número mínimo de empleados para mantener operaciones","El BCP simplificado para PYMES"], c:1, e:"El mínimo viable de negocio define el nivel mínimo aceptable de productos/servicios que la organización debe mantener durante una interrupción para no comprometer su supervivencia o cumplimiento legal." },
    { q:"¿Qué fase del ciclo PDCA corresponde a la ejecución de los planes de continuidad?", o:["Plan","Do (Hacer)","Check (Verificar)","Act (Actuar)"], c:1, e:"La ejecución (implementación y operación) de los planes de continuidad corresponde a la fase Do (Hacer) del ciclo PDCA en ISO 22301." },
    { q:"¿Qué es un ejercicio de 'mesa redonda' (tabletop) en continuidad?", o:["Una reunión para aprobar el BCP","Una simulación basada en discusión donde participantes analizan su respuesta ante un escenario hipotético sin activar sistemas reales","Un ejercicio de evacuación física","Una prueba de recuperación de datos en producción"], c:1, e:"El tabletop es un ejercicio de discusión: el equipo de continuidad analiza conjuntamente cómo respondería ante un escenario dado, identificando gaps sin interrumpir operaciones reales." },
    { q:"¿Qué información debe contener el Plan de Gestión de Crisis en ISO 22301?", o:["Solo la lista de contactos de emergencia","Estructura de gestión de crisis, roles, protocolos de comunicación, criterios de activación y procedimientos de toma de decisiones","El BCP completo","El análisis de riesgos"], c:1, e:"El Plan de Gestión de Crisis define la estructura, roles y responsabilidades del equipo de crisis, protocolos de comunicación interna y externa, criterios de activación y escalado." },
    { q:"¿Qué contempla la 'gestión de proveedores críticos' en ISO 22301?", o:["Auditar anualmente a todos los proveedores","Identificar proveedores críticos, evaluar su continuidad y establecer contractualmente requisitos de disponibilidad y recuperación","Sustituir proveedores por recursos internos","Solo contratar seguros para cubrir fallos de proveedores"], c:1, e:"ISO 22301 exige identificar proveedores críticos (cuyo fallo afecta a actividades esenciales) y asegurar que tienen su propia continuidad o establecer alternativas contractuales." },
    { q:"¿Qué es el 'período de recuperación' en el contexto del BIA?", o:["El tiempo que tarda en activarse el BCP","El período durante el cual se ejecutan las acciones para restaurar la actividad al nivel normal tras superar el modo de contingencia","El plazo de la auditoría post-incidente","El tiempo de inactividad planificada para mantenimiento"], c:1, e:"El período de recuperación es el tiempo necesario para retornar desde el nivel mínimo viable hasta el nivel normal de operación tras una interrupción." },
    { q:"¿Qué diferencia hay entre 'prevención' y 'respuesta' en el contexto de continuidad?", o:["Son sinónimos en ISO 22301","Prevención reduce la probabilidad de que ocurra una interrupción; respuesta gestiona lo que hacer cuando ya ha ocurrido","La prevención es responsabilidad del CISO; la respuesta del COO","Solo la respuesta está cubierta por ISO 22301"], c:1, e:"ISO 22301 abarca ambas: medidas proactivas para reducir la probabilidad de interrupciones (prevención/mitigación) y planes reactivos para responder y recuperarse cuando ocurren (respuesta/recuperación)." },
    { q:"¿Qué es el 'equipo de recuperación de negocio' en ISO 22301?", o:["El departamento de IT","El equipo responsable de ejecutar los procedimientos de continuidad para restaurar actividades específicas tras una interrupción","El comité de dirección","El equipo de auditoría interna"], c:1, e:"El equipo de recuperación de negocio está formado por el personal responsable de ejecutar los BCP para cada actividad crítica, coordinado por el equipo de gestión de crisis." },
    { q:"¿Qué contempla la revisión post-incidente en ISO 22301?", o:["Solo el cálculo de pérdidas económicas","Análisis de causas, evaluación de la respuesta, lecciones aprendidas y actualización de los planes","La comunicación externa post-incidente","El informe para auditores"], c:1, e:"La revisión post-incidente (o post-mortem) en ISO 22301 analiza qué ocurrió, evalúa la eficacia de la respuesta, identifica lecciones aprendidas e incorpora mejoras a los planes." },
    { q:"¿Qué es el 'WAO' (Work Area Recovery) en continuidad?", o:["Un protocolo de comunicación de crisis","La estrategia de recuperación del espacio de trabajo físico cuando la ubicación principal no está disponible","El análisis de impacto en el área de trabajo","Un estándar alternativo a ISO 22301"], c:1, e:"El WAO o Work Area Recovery contempla la disponibilidad de ubicaciones alternativas de trabajo (propias, de terceros o acuerdos de reciprocidad) cuando las instalaciones principales son inaccesibles." },
    { q:"¿Qué información mínima debe contener el BCP según ISO 22301?", o:["Solo los procedimientos de IT","Propósito, alcance, roles, procedimientos de activación, acciones de respuesta por actividad y plan de comunicación","Solo los contactos de emergencia","El presupuesto de contingencia"], c:1, e:"Un BCP completo incluye: propósito y alcance, estructura de respuesta, criterios de activación, procedimientos de recuperación por actividad crítica, recursos necesarios y plan de comunicación." },
    { q:"¿Qué norma complementa a ISO 22301 para la continuidad de servicios TI?", o:["ISO 20000","ISO 27031 (Guidelines for ICT readiness for business continuity)","ITIL v4","ISO 27001"], c:1, e:"ISO 27031 proporciona directrices específicas para la preparación de las TIC en el contexto de la continuidad de negocio, complementando ISO 22301." },
    { q:"¿Qué es el 'apetito de interrupción' en ISO 22301?", o:["El tiempo máximo de inactividad planificado","La cantidad y duración de interrupciones que la organización está dispuesta a tolerar","El presupuesto máximo de recuperación","El número de incidentes anuales aceptable"], c:1, e:"El apetito de interrupción define cuánta disrupción (en términos de frecuencia, duración e impacto) es tolerable para la organización, guiando las decisiones de inversión en continuidad." },
    { q:"¿Qué debe demostrar la alta dirección en ISO 22301?", o:["Conocimiento técnico de los sistemas críticos","Liderazgo y compromiso: integrar el SGCN en los procesos organizativos, asignar recursos y rendir cuentas","Certificación personal en continuidad","Gestión directa de los planes de recuperación"], c:1, e:"La cláusula 5 de ISO 22301 exige que la alta dirección demuestre liderazgo: integrando la continuidad en la estrategia, asignando recursos, comunicando su importancia y rindiendo cuentas." },
    { q:"¿Cuándo debe activarse el BCP?", o:["Solo ante desastres naturales","Cuando se superan los umbrales predefinidos de impacto o duración de una interrupción","Automáticamente ante cualquier incidente","Solo cuando lo decide el CEO"], c:1, e:"El BCP se activa cuando una interrupción supera los umbrales de impacto predefinidos (ligados al MTPD y al tipo de incidente), según los criterios de activación establecidos en el plan." },
    { q:"¿Qué relación tiene el BCP con el plan de gestión de emergencias?", o:["Son el mismo plan","El plan de emergencias gestiona la respuesta inmediata (seguridad de personas); el BCP gestiona la continuidad de actividades de negocio. Son complementarios y secuenciales","El BCP reemplaza al plan de emergencias","Solo aplica el BCP, no son necesarios planes de emergencia"], c:1, e:"Son complementarios: el plan de emergencias actúa primero (seguridad de personas, evacuación). Una vez controlada la emergencia, se activa el BCP para gestionar la continuidad del negocio." },
    { q:"¿Qué es el 'shadow IT' como riesgo para la continuidad?", o:["Software de monitorización no autorizado","Sistemas TI usados en el negocio sin conocimiento ni control del departamento de TI, que pueden quedar fuera del BCP","Copias de seguridad no gestionadas","Accesos remotos no controlados"], c:1, e:"El shadow IT representa sistemas o servicios usados por empleados sin aprobación de TI. Si son críticos para el negocio y no están en el BCP, su fallo puede interrumpir operaciones sin plan de recuperación." },
    { q:"¿Qué tipo de prueba es más completa para validar un BCP?", o:["Revisión documental","Simulacro completo (full-scale exercise) con activación real de procedimientos y sistemas alternativos","Prueba de escritorio (tabletop)","Entrevistas al personal"], c:1, e:"El simulacro completo (full-scale exercise) activa realmente los procedimientos, sistemas alternativos y equipos de respuesta, siendo la prueba más realista pero también la más costosa y arriesgada." },
    { q:"¿Qué es el 'Call Tree' en continuidad de negocio?", o:["Un diagrama de dependencias de sistemas","Un árbol de llamadas: esquema de comunicación en cascada para activar al personal de respuesta ante una interrupción","El organigrama del equipo de crisis","Un protocolo de comunicación con clientes"], c:1, e:"El Call Tree define el flujo de comunicación en caso de activación del BCP: quién llama a quién y en qué orden, garantizando que todo el personal clave sea notificado rápidamente." }
  ],

  // ══════════════════════════════════════════════════════════
  "Zero Trust Architecture": [
    { q:"¿Cuál es el principio fundamental de Zero Trust?", o:["Confiar en la red interna y desconfiar de la externa","Nunca confiar, siempre verificar (Never Trust, Always Verify)","Denegar todo el tráfico por defecto sin excepciones","Confiar en los usuarios internos y verificar solo a externos"], c:1, e:"Zero Trust se basa en 'Never Trust, Always Verify': ningún usuario, dispositivo o red es de confianza por defecto, independientemente de si está dentro o fuera del perímetro corporativo." },
    { q:"¿Qué organismo publicó el marco de referencia Zero Trust Architecture (SP 800-207)?", o:["ISO","NIST (National Institute of Standards and Technology)","ENISA","CIS Controls"], c:1, e:"NIST publicó el Special Publication 800-207 'Zero Trust Architecture' en 2020, que es el marco de referencia más utilizado para implementar arquitecturas Zero Trust." },
    { q:"¿Qué es la microsegmentación en Zero Trust?", o:["Dividir la red en segmentos VLAN grandes","Dividir la red en zonas pequeñas con controles de acceso granulares para limitar el movimiento lateral","Segmentar los datos por nivel de clasificación","Separar la red de producción de la de desarrollo"], c:1, e:"La microsegmentación divide la red en pequeños segmentos con políticas de acceso granulares, impidiendo que un atacante que compromete un segmento se mueva lateralmente a otros." },
    { q:"¿Qué es el 'Policy Enforcement Point' (PEP) en Zero Trust?", o:["El servidor de autenticación","El componente que concede, deniega o revoca el acceso a recursos basándose en las decisiones del Policy Decision Point","El firewall perimetral","El directorio de identidades"], c:1, e:"El PEP es el mecanismo que aplica las decisiones de acceso: concede, deniega o revoca las conexiones a recursos protegidos basándose en las instrucciones del Policy Decision Point (PDP)." },
    { q:"¿Por qué Zero Trust es especialmente relevante en entornos de trabajo remoto e híbrido?", o:["Porque elimina la necesidad de VPN completamente","Porque el perímetro tradicional ya no existe: usuarios y datos están fuera de la red corporativa, haciendo insuficiente el modelo de confianza basado en ubicación","Porque es más barato que mantener una VPN","Porque solo funciona en entornos cloud"], c:1, e:"El trabajo remoto desdibuja el perímetro corporativo: usuarios acceden desde múltiples ubicaciones y dispositivos. Zero Trust verifica continuamente la identidad y el contexto, siendo más seguro que confiar en la red de origen." },
    { q:"¿Qué rol juega la identidad en Zero Trust?", o:["Es uno de los factores entre muchos, sin papel central","La identidad es el nuevo perímetro: toda decisión de acceso se basa en verificar quién solicita el acceso","Solo aplica a cuentas de administrador","La identidad es gestionada exclusivamente por el directorio activo"], c:1, e:"En Zero Trust, la identidad es el nuevo perímetro de seguridad. Toda solicitud de acceso requiere verificación de identidad robusta, independientemente de la ubicación o la red." },
    { q:"¿Qué es el 'acceso con mínimos privilegios' en Zero Trust?", o:["Dar acceso solo a administradores","Conceder a cada usuario solo los permisos estrictamente necesarios para realizar su función, ni más ni menos","Limitar el acceso a horario laboral","Usar contraseñas complejas para todos los accesos"], c:1, e:"El principio de mínimo privilegio (Least Privilege) en Zero Trust garantiza que cada identidad accede únicamente a los recursos que necesita para su función, reduciendo la superficie de ataque." },
    { q:"¿Qué es ZTNA (Zero Trust Network Access)?", o:["Una VPN mejorada con cifrado adicional","Un paradigma que proporciona acceso remoto seguro a aplicaciones específicas sin exponer la red, verificando identidad y contexto en cada solicitud","Un protocolo de red basado en Zero Trust","El sustituto oficial de los firewalls"], c:1, e:"ZTNA reemplaza a la VPN tradicional: en lugar de dar acceso a la red, proporciona acceso granular a aplicaciones específicas tras verificar identidad, dispositivo y contexto." },
    { q:"¿Cuáles son los tres pilares principales de Zero Trust según NIST SP 800-207?", o:["Red, identidad y datos","Usuarios/identidades, dispositivos y redes/aplicaciones/datos (los 7 pilares de ZTA)","Autenticación, autorización y auditoría","Prevención, detección y respuesta"], c:1, e:"NIST SP 800-207 identifica 7 pilares: identidades, dispositivos, redes, cargas de trabajo (aplicaciones), datos, visibilidad/analítica y automatización/orquestación." },
    { q:"¿Qué significa 'asumir la brecha' (Assume Breach) en Zero Trust?", o:["Aceptar que ocurrirán incidentes sin invertir en prevención","Diseñar los sistemas asumiendo que el atacante ya está dentro, implementando controles para minimizar el impacto","Notificar preventivamente a los reguladores","Contratar un seguro cibernético antes de implementar controles"], c:1, e:"'Assume Breach' es uno de los principios Zero Trust: diseñar y operar los sistemas como si el atacante ya hubiera comprometido la red, minimizando el radio de explosión mediante segmentación y monitorización." },
    { q:"¿Qué es el 'Policy Decision Point' (PDP) en Zero Trust?", o:["El firewall de nueva generación","El componente que evalúa las solicitudes de acceso contra las políticas y decide si conceder o denegar","El servidor RADIUS","El gestor de identidades"], c:1, e:"El PDP (también llamado Policy Engine + Policy Administrator) evalúa cada solicitud de acceso considerando identidad, dispositivo, red y contexto, y emite la decisión que aplica el PEP." },
    { q:"¿Cómo se relaciona Zero Trust con SASE (Secure Access Service Edge)?", o:["Son conceptos incompatibles","SASE es una arquitectura cloud que integra principios Zero Trust (ZTNA) con capacidades de red (SD-WAN) y seguridad (SWG, CASB, FWaaS) en un servicio unificado","SASE reemplaza completamente a Zero Trust","Zero Trust solo puede implementarse con SASE"], c:1, e:"SASE (Gartner, 2019) converge red y seguridad en la nube, incorporando ZTNA como componente de acceso. Es una implementación arquitectónica que incluye principios Zero Trust junto a SD-WAN y otros servicios." },
    { q:"¿Qué es el 'contexto' en la evaluación de acceso Zero Trust?", o:["La ubicación física del usuario","El conjunto de señales que rodean una solicitud de acceso: dispositivo, ubicación, hora, comportamiento, riesgo de identidad, etc.","El nivel jerárquico del solicitante","El tipo de datos solicitados únicamente"], c:1, e:"El contexto en Zero Trust incluye múltiples señales: estado del dispositivo, ubicación, hora, comportamiento previo, nivel de riesgo de la identidad, sensibilidad del recurso, etc. Todo ello informa la decisión de acceso." },
    { q:"¿Qué papel juega el MFA en Zero Trust?", o:["Es opcional si la contraseña es compleja","Es un control fundamental: la autenticación multifactor verifica que el solicitante es quien dice ser antes de evaluar el contexto","Solo aplica para accesos externos","Reemplaza a la evaluación de contexto"], c:1, e:"El MFA es un componente básico de Zero Trust: verifica la identidad con múltiples factores antes de proceder a la evaluación del contexto y la decisión de acceso." },
    { q:"¿Qué es el 'movimiento lateral' y cómo lo mitiga Zero Trust?", o:["El movimiento de datos entre nubes; mitigado con CASB","El desplazamiento de un atacante a través de la red tras comprometer un sistema; Zero Trust lo mitiga con microsegmentación y verificación continua","El acceso desde múltiples ubicaciones; mitigado con ZTNA","El tráfico entre servidores; mitigado con cifrado"], c:1, e:"El movimiento lateral es cómo los atacantes se expanden tras un compromiso inicial. Zero Trust lo mitiga mediante microsegmentación (limita el alcance) y verificación continua (detecta comportamiento anómalo)." },
    { q:"¿Qué es un 'recurso protegido' en la arquitectura Zero Trust?", o:["Cualquier servidor en la red corporativa","Todo activo (datos, aplicación, servicio, dispositivo) cuyo acceso debe ser verificado y controlado por el PEP","Solo los datos clasificados como confidenciales","Los sistemas legacy fuera del alcance ZT"], c:1, e:"En ZTA, un recurso protegido es cualquier activo valioso cuyo acceso debe pasar por el Policy Enforcement Point, aplicando la decisión del Policy Decision Point." },
    { q:"¿Cómo aborda Zero Trust el acceso de terceros y proveedores?", o:["Los terceros se excluyen del modelo Zero Trust","Los terceros son tratados como cualquier otro usuario: verificación de identidad, dispositivo y contexto antes de cada acceso, con mínimo privilegio","Los terceros acceden por VPN dedicada sin verificación adicional","Solo se permite acceso de terceros desde la red corporativa"], c:1, e:"Zero Trust trata a terceros y proveedores como cualquier identidad: verificación robusta, acceso granular solo a los recursos necesarios para su función y monitorización continua." },
    { q:"¿Qué es la 'inspección y registro de todo el tráfico' en Zero Trust?", o:["Guardar todos los logs durante 10 años","Monitorizar, registrar y analizar todo el tráfico de red para detectar anomalías, independientemente de su origen","Solo inspeccionar el tráfico externo","Inspeccionar únicamente el tráfico cifrado"], c:1, e:"Zero Trust exige visibilidad completa: todo el tráfico (interno y externo) debe ser inspeccionado, registrado y analizado para detectar comportamientos anómalos y permitir la forensia post-incidente." },
    { q:"¿Qué es un 'control plane' en Zero Trust?", o:["El plano de red donde circulan los datos","El plano lógico donde se toman las decisiones de acceso (Policy Engine y Policy Administrator)","El dashboard de monitorización","El sistema de gestión de identidades"], c:1, e:"El control plane en ZTA es el plano lógico de decisión: contiene el Policy Engine y el Policy Administrator, que evalúan las solicitudes y emiten decisiones. El data plane es donde fluyen realmente los datos." },
    { q:"¿Qué tecnología es fundamental para Zero Trust en entornos multicloud?", o:["MPLS dedicada entre nubes","CASB (Cloud Access Security Broker) para visibilidad y control de acceso a servicios cloud, complementado con ZTNA","VPN site-to-site entre los proveedores cloud","Replicación sincrónica de datos entre nubes"], c:1, e:"Los CASB son fundamentales en entornos multicloud: proporcionan visibilidad, control de acceso y protección de datos para los servicios cloud, integrándose con los principios Zero Trust." },
    { q:"¿Por qué los modelos de confianza basados en VPN son insuficientes frente a Zero Trust?", o:["Las VPN son más lentas que ZTNA","La VPN otorga acceso a la red completa una vez autenticado, sin verificación continua ni segmentación; Zero Trust verifica continuamente y limita el acceso a recursos específicos","Las VPN no soportan MFA","Las VPN son demasiado caras para grandes organizaciones"], c:1, e:"La VPN tradicional es un modelo de 'castillo y foso': autenticado el usuario, accede a la red interna completa. Si un atacante compromete una sesión VPN, tiene acceso total. Zero Trust limita el acceso y verifica continuamente." },
    { q:"¿Qué es el 'device trust' en Zero Trust?", o:["Confiar en dispositivos corporativos sin verificación","Evaluar el estado de seguridad del dispositivo (parches, antivirus, configuración) antes de permitir el acceso","Solo verificar que el dispositivo está registrado en el MDM","Limitar el acceso a dispositivos de propiedad corporativa"], c:1, e:"El device trust evalúa el estado de salud del dispositivo (compliance): versión de OS, parches, presencia de EDR, cifrado de disco, integridad de la configuración. Un dispositivo no conforme puede recibir acceso limitado o denegado." },
    { q:"¿Cómo implementa Zero Trust el principio de 'acceso justo a tiempo' (JIT)?", o:["Dando acceso permanente solo durante el horario laboral","Proporcionando acceso privilegiado solo cuando es necesario, por el tiempo mínimo y con aprobación explícita, eliminándolo automáticamente después","Limitando el acceso a 8 horas diarias","Solo aplicable a cuentas de servicio"], c:1, e:"El acceso JIT (Just-in-Time) elimina los privilegios permanentes: el acceso elevado se concede bajo demanda, solo cuando es necesario, durante el tiempo mínimo y con aprobación, reduciendo la superficie de ataque." },
    { q:"¿Qué es el marco BeyondCorp de Google en relación con Zero Trust?", o:["Una herramienta de Google Cloud para CASB","La implementación pionera de Zero Trust de Google, que eliminó el concepto de red interna de confianza y exige verificación de identidad y dispositivo para todos los accesos","Un competidor de NIST SP 800-207","Un protocolo de red propietario"], c:1, e:"BeyondCorp es la implementación de Zero Trust de Google, iniciada en 2011 y documentada públicamente. Eliminó la VPN corporativa y exige verificación de identidad + estado del dispositivo para cada acceso, independientemente de la red." },
    { q:"¿Qué métricas son clave para medir la madurez de Zero Trust?", o:["Solo el número de incidentes de seguridad","Cobertura de MFA, porcentaje de tráfico inspeccionado, tiempo de detección de anomalías, cobertura de microsegmentación y madurez de gestión de identidades","El presupuesto invertido en ZT","El número de usuarios migrados a ZTNA"], c:1, e:"La madurez ZT se mide en múltiples dimensiones: adopción de MFA, cobertura de microsegmentación, % tráfico cifrado e inspeccionado, tiempo de detección/respuesta y nivel de automatización de políticas." },
    { q:"¿Qué es el modelo de madurez Zero Trust de CISA?", o:["Una certificación oficial de Zero Trust","Un marco de referencia con 5 pilares y niveles de madurez (tradicional, inicial, avanzado, óptimo) para guiar la adopción progresiva de ZT","Un requerimiento obligatorio para agencias federales EEUU","Un sustituto de NIST SP 800-207"], c:1, e:"El CISA Zero Trust Maturity Model define 5 pilares (identidad, dispositivos, redes, aplicaciones/cargas de trabajo, datos) con niveles de madurez para ayudar a las organizaciones a planificar su adopción progresiva." },
    { q:"¿Cómo aborda Zero Trust la seguridad de las cargas de trabajo en cloud?", o:["Aplicando el mismo perímetro de red que en on-premise","Usando microsegmentación de workloads, identidades de carga de trabajo, cifrado en tránsito e inspección de APIs como puntos de control ZT","Delegando la seguridad completamente al proveedor cloud","Solo cifrando los datos almacenados"], c:1, e:"En cloud, Zero Trust protege las cargas de trabajo mediante: identidades de workload (no solo de usuario), microsegmentación entre servicios, inspección de tráfico este-oeste y APIs como perímetro de control." },
    { q:"¿Qué es el 'radio de explosión' (blast radius) y cómo lo reduce Zero Trust?", o:["El área física afectada por un incidente físico","El alcance del daño cuando un atacante compromete un sistema; Zero Trust lo reduce con microsegmentación y mínimo privilegio, limitando el movimiento lateral","El impacto reputacional de una brecha","El coste económico de un incidente de seguridad"], c:1, e:"El blast radius es cuánto daño puede hacer un atacante tras comprometer un sistema. Zero Trust lo minimiza: la microsegmentación contiene el movimiento lateral y el mínimo privilegio limita los recursos accesibles desde el sistema comprometido." },
    { q:"¿Qué papel juega la automatización en una arquitectura Zero Trust madura?", o:["La automatización es opcional en ZT","La automatización es esencial: permite respuesta dinámica a cambios de riesgo, ajuste automático de políticas y orquestación de controles sin intervención manual constante","Solo automatizar la generación de informes","Automatizar únicamente la rotación de contraseñas"], c:1, e:"En ZT maduro, la automatización orquesta respuestas dinámicas: si un dispositivo pierde compliance o una identidad muestra comportamiento anómalo, las políticas se ajustan automáticamente sin esperar intervención humana." }
  ],

  // ══════════════════════════════════════════════════════════
  "DORA (Digital Operational Resilience)": [
    { q:"¿A qué sector aplica principalmente el Reglamento DORA?", o:["Sector industrial y manufactura","Sector financiero: entidades de crédito, aseguradoras, gestoras, plataformas de criptoactivos y sus proveedores TIC críticos","Todo el sector privado europeo","Solo bancos sistémicos"], c:1, e:"DORA (Reglamento 2022/2554) aplica a entidades financieras reguladas en la UE (bancos, aseguradoras, gestoras, criptoactivos, etc.) y a sus proveedores TIC de terceros considerados críticos." },
    { q:"¿Cuándo es de aplicación obligatoria DORA?", o:["Enero 2023","17 de enero de 2025","1 de enero de 2026","Octubre 2024"], c:1, e:"DORA entró en vigor en enero de 2023 pero su aplicación obligatoria se fijó para el 17 de enero de 2025, dando 2 años de adaptación a las entidades." },
    { q:"¿Cuáles son los 5 pilares de DORA?", o:["Prevención, detección, respuesta, recuperación y comunicación","Gestión del riesgo TIC, gestión de incidentes, pruebas de resiliencia, riesgo de terceros y compartición de información","Gobernanza, riesgo, compliance, continuidad y auditoría","Identidad, datos, red, aplicaciones y dispositivos"], c:1, e:"Los 5 pilares de DORA son: gestión del riesgo TIC, gestión y notificación de incidentes, pruebas de resiliencia operativa digital, riesgo de terceros proveedores TIC e intercambio de información." },
    { q:"¿Qué es el TLPT en el contexto de DORA?", o:["Threat-Led Penetration Testing: pruebas de penetración guiadas por inteligencia de amenazas reales, obligatorias para entidades significativas","Total Loss Prevention Testing: pruebas de continuidad total","Third-Level Provider Testing: auditoría de proveedores de tercer nivel","Technology Lifecycle Planning Tool: herramienta de planificación"], c:0, e:"El TLPT (Threat-Led Penetration Testing) es una prueba avanzada de resiliencia basada en inteligencia de amenazas reales, que simula ataques APT contra los sistemas de producción, obligatoria para entidades significativas bajo DORA." },
    { q:"¿Qué plazo establece DORA para notificar incidentes TIC graves a la autoridad competente?", o:["72 horas","Notificación inicial en 4 horas si el umbral se supera; informe intermedio en 72 horas; informe final en 1 mes","24 horas para todos los incidentes","7 días hábiles"], c:1, e:"DORA establece un proceso escalonado: alerta temprana en 4 horas (si se supera el umbral), notificación inicial en 72 horas e informe final en 1 mes tras la resolución del incidente." },
    { q:"¿Qué son los 'proveedores TIC críticos de terceros' (CTPP) en DORA?", o:["Cualquier proveedor de servicios cloud","Proveedores TIC designados por las ESAs como críticos por la concentración de riesgo sistémico que representan para el sector financiero","Todos los proveedores con más de 500 empleados","Solo proveedores de infraestructura de pagos"], c:1, e:"Las ESAs (EBA, ESMA, EIOPA) designan a los proveedores TIC de terceros como críticos (CTPP) cuando su concentración sistémica puede generar riesgo para la estabilidad financiera de la UE." },
    { q:"¿Qué marco de supervisión establece DORA para los CTPP?", o:["Autoevaluación anual","Supervisión directa por las ESAs con evaluaciones, inspecciones y potestades de sanción","Supervisión por las autoridades nacionales de cada Estado Miembro","Certificación voluntaria por terceros"], c:1, e:"DORA crea un marco de supervisión directa de los CTPP por las ESAs (EBA, ESMA, EIOPA), que pueden realizar evaluaciones, inspecciones in situ y remotas, y emitir recomendaciones vinculantes." },
    { q:"¿Qué exige DORA sobre la estrategia de resiliencia operativa digital?", o:["Un documento de política aprobado por el departamento de IT","Una estrategia aprobada por el órgano de dirección que integre la resiliencia TIC en la estrategia de negocio","Solo un BCP actualizado","Un plan de auditoría anual"], c:1, e:"DORA exige que el órgano de dirección apruebe y supervise una estrategia de resiliencia operativa digital integrada en la estrategia de negocio, siendo personalmente responsable de su eficacia." },
    { q:"¿Qué obligación establece DORA sobre el registro de incidentes TIC?", o:["Solo registrar incidentes que superen el umbral de notificación","Mantener un registro de todos los incidentes TIC, clasificados según su impacto, independientemente de si se notifican a la autoridad","Solo los incidentes de ciberseguridad","Registro únicamente de los incidentes que afecten a clientes"], c:1, e:"DORA exige un registro exhaustivo de todos los incidentes TIC, con clasificación según criterios predefinidos (duración, impacto, criticidad), independientemente de si superan el umbral de notificación regulatoria." },
    { q:"¿Cómo aborda DORA el riesgo de concentración en proveedores cloud?", o:["Prohíbe usar más de 2 proveedores cloud","Exige análisis del riesgo de concentración y estrategias de salida para evitar dependencia excesiva de un único proveedor TIC","Solo requiere auditar a los proveedores cloud anualment","El riesgo de concentración se gestiona solo a nivel de sector, no de entidad"], c:1, e:"DORA obliga a las entidades a analizar el riesgo de concentración (dependencia de un único o pocos proveedores críticos) y a tener estrategias de salida (exit strategies) para reducir esa dependencia." },
    { q:"¿Qué diferencia DORA de NIS2 en el sector financiero?", o:["Son equivalentes; las entidades financieras pueden elegir cuál cumplir","DORA es lex specialis para el sector financiero: sus requisitos más específicos prevalecen sobre NIS2 para entidades financieras en materias de resiliencia TIC","NIS2 incluye todos los requisitos de DORA y más","DORA solo aplica a grandes bancos; NIS2 al resto del sector financiero"], c:1, e:"DORA aplica el principio lex specialis: es la norma específica para el sector financiero. Las entidades financieras aplican DORA para resiliencia TIC, mientras que NIS2 tiene carácter más general." },
    { q:"¿Qué exige DORA sobre las pruebas de resiliencia operativa?", o:["Solo pruebas de penetración externas cada 5 años","Un programa anual de pruebas que incluya desde evaluaciones de vulnerabilidades hasta TLPT para entidades significativas","Solo pruebas de recuperación de datos","Pruebas opcionales a criterio de la entidad"], c:1, e:"DORA exige un programa completo de pruebas: evaluaciones de vulnerabilidades, pruebas de continuidad, análisis de gaps y TLPT (basado en inteligencia de amenazas) para entidades significativas, con un mínimo de periodicidad." },
    { q:"¿Qué información debe incluir el informe de incidentes graves bajo DORA?", o:["Solo el tipo de incidente y el impacto económico","Clasificación, impacto en clientes y contrapartes, causa raíz, medidas adoptadas, impacto transfronterizo y lecciones aprendidas","Solo el número de clientes afectados","El coste total de recuperación"], c:1, e:"El informe DORA de incidentes graves debe incluir: clasificación del incidente, impacto en clientes/contrapartes, causa raíz, medidas de respuesta y recuperación, impacto transfronterizo potencial y lecciones aprendidas." },
    { q:"¿Qué son las 'exit strategies' exigidas por DORA?", o:["Planes de salida para empleados clave","Estrategias documentadas para terminar contratos con proveedores TIC críticos sin interrumpir operaciones, incluyendo planes de transición y proveedores alternativos","Planes de desinversión financiera","Protocolos de cierre de sistemas legacy"], c:1, e:"Las exit strategies (estrategias de salida) son planes documentados para terminar la relación con un proveedor TIC crítico, garantizando continuidad operativa durante la transición hacia un proveedor alternativo." },
    { q:"¿Qué papel tiene el 'órgano de dirección' en DORA?", o:["Delega toda la responsabilidad TIC al CISO","Es personalmente responsable de la resiliencia operativa digital: aprueba la estrategia, supervisa su implementación y responde ante los supervisores","Solo aprueba el presupuesto de IT","Su rol es estrictamente de supervisión pasiva"], c:1, e:"DORA establece responsabilidad personal del órgano de dirección: debe comprender los riesgos TIC, aprobar la estrategia de resiliencia, supervisar su implementación y puede ser sancionado personalmente por incumplimientos." },
    { q:"¿Qué es el 'marco de gestión del riesgo TIC' exigido por DORA?", o:["Un inventario de activos TIC","Un sistema integral que cubra identificación, protección, detección, respuesta y recuperación ante riesgos TIC, revisado anualmente y aprobado por la dirección","Solo las políticas de ciberseguridad","El plan de auditoría interna de IT"], c:1, e:"El marco de gestión del riesgo TIC de DORA es integral: identifica activos críticos, implementa controles (protección, detección, respuesta, recuperación), tiene métricas de eficacia y es aprobado y revisado por el órgano de dirección." },
    { q:"¿Cómo regula DORA los contratos con proveedores TIC críticos?", o:["Solo exige que los contratos sean por escrito","Establece cláusulas contractuales mínimas obligatorias: niveles de servicio, derecho de auditoría, continuidad, subcontratación, localización de datos y exit strategy","Los contratos son responsabilidad exclusiva del área legal","Solo para contratos superiores a 1 millón de euros"], c:1, e:"DORA establece cláusulas contractuales mínimas para contratos con proveedores TIC: SLAs específicos, derecho de auditoría, requisitos de continuidad, condiciones de subcontratación, localización de datos y condiciones de terminación." },
    { q:"¿Qué es el intercambio de información sobre ciberamenazas en DORA?", o:["Una obligación de compartir toda la información de incidentes públicamente","La posibilidad (voluntaria, con salvaguardas) de que entidades financieras compartan inteligencia sobre amenazas dentro del sector para mejorar la resiliencia colectiva","Un requisito de notificación adicional al de incidentes","La publicación obligatoria de vulnerabilidades explotadas"], c:1, e:"DORA fomenta el intercambio voluntario de inteligencia sobre ciberamenazas entre entidades financieras, con salvaguardas de confidencialidad, como complemento a los requisitos de notificación de incidentes." },
    { q:"¿Qué supervisores son responsables de la implementación de DORA?", o:["Solo el BCE para entidades bancarias","Las ESAs (EBA, ESMA, EIOPA) a nivel europeo y las autoridades nacionales competentes (p.ej. BdE, CNMV, DGSFP en España) a nivel nacional","Solo autoridades nacionales","ENISA como supervisor técnico único"], c:1, e:"DORA tiene una estructura de supervisión doble: las ESAs (EBA, ESMA, EIOPA) supervisan a los CTPP directamente; las autoridades nacionales competentes (BdE, CNMV, etc.) supervisan a las entidades financieras individuales." },
    { q:"¿Cómo clasifica DORA los incidentes TIC para determinar si son 'graves'?", o:["Solo por el impacto económico directo","Por criterios multidimensionales: número de clientes afectados, duración, pérdida de datos, criticidad de servicios, impacto reputacional y geográfico","Solo por el número de sistemas afectados","Por decisión discrecional del CISO"], c:1, e:"DORA define criterios de clasificación de incidentes graves: clientes afectados, duración, pérdida de datos, impacto en servicios críticos, alcance geográfico e impacto reputacional. Las ESAs han publicado RTS técnicos con los umbrales exactos." },
    { q:"¿Qué exige DORA sobre la función de control del riesgo TIC?", o:["Puede ser gestionada por el propio departamento IT","Debe existir una función independiente de control del riesgo TIC (o un CISO) con independencia suficiente del área de negocio","Solo aplica a entidades con más de 500 empleados","Es suficiente con el comité de auditoría"], c:1, e:"DORA exige que entidades significativas dispongan de una función de control del riesgo TIC independiente, con acceso directo al órgano de dirección y recursos suficientes para realizar su función." },
    { q:"¿Qué son los RTS y GL que complementan DORA?", o:["Registros de Tratamiento de Seguridad","Regulatory Technical Standards y Guidelines publicados por las ESAs con requisitos técnicos detallados para implementar DORA","Requerimientos Técnicos de Supervisión del BCE","Guías de las autoridades nacionales"], c:1, e:"Los RTS (Regulatory Technical Standards) y GL (Guidelines) son actos delegados y orientaciones publicados por EBA, ESMA y EIOPA que detallan los requisitos técnicos de DORA (clasificación de incidentes, pruebas TLPT, contratos con terceros, etc.)." },
    { q:"¿Qué obligación establece DORA sobre los planes de continuidad TIC?", o:["Un BCP genérico actualizado cada 3 años","Planes de continuidad TIC específicos, probados regularmente, que incluyan escenarios de ciberataque y garanticen la continuidad de funciones críticas","Solo planes de recuperación de datos","Planes de continuidad solo para sistemas de pago"], c:1, e:"DORA exige planes de continuidad TIC específicos (no solo genéricos) que contemplen escenarios de ciberataque, sean probados regularmente y garanticen la continuidad de funciones y servicios críticos." },
    { q:"¿Qué implica para las fintech y neobancos el ámbito de aplicación de DORA?", o:["Están exentos por su tamaño","Están incluidos si están autorizados como entidades financieras en la UE, con posibles proporcionalidad en algunos requisitos según su tamaño","Solo aplica DORA a los bancos tradicionales","Solo si operan en más de 3 países de la UE"], c:1, e:"Las fintech y neobancos con licencia financiera en la UE (EMI, entidades de pago, entidades de crédito) están incluidos en DORA, aunque el reglamento permite proporcionalidad en algunos requisitos para entidades más pequeñas o menos complejas." },
    { q:"¿Qué sanciones puede imponer DORA a las entidades financieras incumplidoras?", o:["Solo sanciones administrativas sin límite definido","Las autoridades nacionales pueden imponer sanciones (cuyo régimen detalla cada Estado Miembro), y las ESAs pueden emitir recomendaciones a los CTPP con potencial impacto reputacional","Solo advertencias públicas","Sanciones penales directas a los directivos"], c:1, e:"El régimen sancionador de DORA se implementa por las autoridades nacionales (con marcos propios) para entidades financieras. Para CTPP, las ESAs pueden emitir recomendaciones públicas y, en última instancia, las autoridades nacionales pueden imponer sanciones." },
    { q:"¿Cuál es la relación entre DORA y los requisitos de capital (Basilea III/CRR)?", o:["DORA sustituye a los requisitos de capital operacional","Son complementarios: los requisitos de capital cubren el riesgo operacional financiero; DORA refuerza la resiliencia operativa TIC que subyace a ese riesgo","DORA modifica directamente el CRR","No tienen relación"], c:1, e:"DORA y los requisitos de capital (Basilea III, CRR) son complementarios: los requisitos de capital reflejan el riesgo operacional (incluido TIC) en términos financieros; DORA refuerza los controles operativos que reducen ese riesgo." },
    { q:"¿Qué papel juegan los acuerdos de nivel de servicio (SLA) en DORA?", o:["Son opcionales para proveedores TIC no críticos","Son obligatorios y deben incluir objetivos de rendimiento medibles, requisitos de disponibilidad, tiempos de respuesta ante incidentes y penalizaciones, formando parte de las cláusulas contractuales mínimas","Solo aplican a contratos de cloud público","Deben ser aprobados por las ESAs"], c:1, e:"Los SLA son parte de las cláusulas contractuales mínimas de DORA: deben incluir objetivos de rendimiento cuantificables, disponibilidad, tiempos de respuesta y resolución de incidentes y mecanismos de penalización por incumplimiento." },
    { q:"¿Qué es la 'función de auditoría TIC' en el marco de DORA?", o:["El departamento de IT que autoevalúa su seguridad","Una función de auditoría interna o externa que evalúa de forma independiente el marco de gestión del riesgo TIC, identificando gaps y recomendando mejoras","El CISO que reporta al CEO","El comité de riesgos del consejo"], c:1, e:"DORA exige auditorías independientes del marco de gestión del riesgo TIC, realizadas por auditores internos con competencia TIC o por auditores externos, que reporten directamente al órgano de dirección." }
  ],

  // ══════════════════════════════════════════════════════════
  "Ransomware Defense": [
    { q:"¿Cuál es el vector de entrada más común para ransomware en entornos corporativos?", o:["Ataques físicos a servidores","Phishing/spear-phishing y explotación de VPNs/RDP vulnerables","Ataques de fuerza bruta a redes WiFi","Infección por USBs en equipos de producción"], c:1, e:"El phishing (correos maliciosos con adjuntos o enlaces) y la explotación de accesos remotos (VPN desactualizadas, RDP expuesto) son los vectores más frecuentes de entrada de ransomware según CISA, Europol y los principales vendors de seguridad." },
    { q:"¿Qué es el modelo 3-2-1 de copias de seguridad y por qué es crítico contra ransomware?", o:["3 copias en 3 ubicaciones, 2 formatos, 1 backup offline: garantiza recuperación incluso si el ransomware cifra los backups online","3 backups diarios, 2 semanales, 1 mensual","3 tipos de datos, 2 responsables, 1 auditoría anual","3 copias locales, 2 en la nube, 1 en cinta"], c:0, e:"El modelo 3-2-1 (3 copias, 2 medios distintos, 1 offline/air-gapped) es fundamental: el ransomware moderno ataca activamente los backups accesibles. La copia offline o inmutable garantiza la recuperación sin pagar el rescate." },
    { q:"¿Qué es el 'double extortion' en ransomware moderno?", o:["Dos grupos atacantes que exigen rescate simultáneamente","El atacante cifra los datos Y los exfiltra, amenazando con publicarlos si no se paga aunque se restaure desde backup","Atacar dos veces al mismo objetivo","Exigir el doble del rescate inicial"], c:1, e:"La doble extorsión (double extortion) combina cifrado de datos con exfiltración previa: el atacante amenaza con publicar los datos robados en sitios de leak aunque la víctima restaure desde backups, añadiendo presión para pagar." },
    { q:"¿Qué es el 'tiempo de permanencia' (dwell time) en un ataque de ransomware?", o:["El tiempo que tarda en ejecutarse el cifrado","El tiempo que el atacante permanece en la red antes de desplegar el ransomware, durante el cual reconoce la red y compromete cuentas privilegiadas","El tiempo de respuesta del equipo de IR","El tiempo total del incidente desde detección hasta recuperación"], c:1, e:"El dwell time es el tiempo entre el compromiso inicial y la ejecución del ransomware. En ataques sofisticados puede ser semanas o meses: el atacante se mueve lateralmente, eleva privilegios y posiciona el ransomware antes de activarlo." },
    { q:"¿Qué control es más efectivo para limitar el impacto de un ransomware que ya ha entrado en la red?", o:["Antivirus actualizado","Segmentación de red y mínimo privilegio: limitan el movimiento lateral y el acceso a datos y backups","Firewall perimetral","Política de contraseñas complejas"], c:1, e:"Una vez dentro, la segmentación de red contiene el ransomware en un segmento limitado; el mínimo privilegio impide que las cuentas comprometidas accedan a todos los sistemas. Ambos reducen el blast radius." },
    { q:"¿Por qué el RDP (Remote Desktop Protocol) es un vector de ataque frecuente para ransomware?", o:["Es un protocolo obsoleto sin cifrado","Muchas organizaciones lo exponen directamente a Internet con credenciales débiles o sin MFA, facilitando el acceso por fuerza bruta o credenciales robadas","Solo es vulnerable en Windows XP","El RDP no tiene mecanismos de autenticación"], c:1, e:"El RDP expuesto en Internet sin MFA y con credenciales débiles es uno de los vectores preferidos: los atacantes escanean Internet buscando puertos 3389 y atacan por fuerza bruta o usan credenciales compradas en la dark web." },
    { q:"¿Qué es el 'ransomware-as-a-service' (RaaS)?", o:["Software antirransomware vendido como servicio","Un modelo de negocio criminal donde los desarrolladores de ransomware alquilan su infraestructura a afiliados que realizan los ataques, compartiendo el rescate","Un servicio de recuperación ante ransomware","Una plataforma de backup como servicio"], c:1, e:"RaaS es el modelo de negocio dominante en ransomware: los grupos desarrolladores (Akira, LockBit, BlackCat) alquilan su ransomware y su infraestructura a afiliados que ejecutan los ataques, compartiendo los rescates (típicamente 70-80% para el afiliado)." },
    { q:"¿Cuál debe ser la primera acción al detectar un incidente de ransomware activo?", o:["Pagar el rescate para recuperar los datos rápidamente","Aislar los sistemas afectados de la red para contener la propagación, preservando evidencias","Apagar todos los sistemas de la empresa","Llamar al proveedor de antivirus"], c:1, e:"La contención inmediata mediante aislamiento de red (desconectar sistemas afectados de la LAN/WAN) es la primera acción crítica: detiene la propagación lateral. Se hace preservando evidencias (no apagar discos duros si es posible)." },
    { q:"¿Qué herramienta gratuita permite intentar descifrar archivos afectados por ransomware conocido?", o:["HaveIBeenPwned","No More Ransom (nomoreransom.org) con herramientas de descifrado de Europol, Kaspersky, ESET y otros","VirusTotal","Shodan"], c:1, e:"No More Ransom (nomoreransom.org) es la iniciativa de Europol, Politie NL y empresas de ciberseguridad que ofrece herramientas gratuitas de descifrado para decenas de familias de ransomware." },
    { q:"¿Qué es el 'exfiltration' en el contexto del ransomware moderno?", o:["La encriptación de datos","La copia y envío de datos al servidor del atacante antes de cifrarlos, para usarlos como palanca de extorsión adicional","El movimiento lateral del ransomware","La demanda de rescate"], c:1, e:"La exfiltración es el robo de datos que precede al cifrado en ataques de doble extorsión: el atacante exfiltra datos sensibles a sus servidores y luego los usa como amenaza adicional ('paga o publicamos tus datos')." },
    { q:"¿Por qué deshabilitar las macros de Office por defecto es una defensa anti-ransomware?", o:["Las macros ralentizan los equipos","Las macros maliciosas en documentos Office son uno de los mecanismos más frecuentes de ejecución de ransomware mediante phishing","Las macros consumen mucho ancho de banda","Las macros son vulnerabilidades de día cero"], c:1, e:"Los documentos Office con macros maliciosas son uno de los vectores de phishing más utilizados para ejecutar código inicial (dropper) que descarga e instala el ransomware. Deshabilitar macros por GPO elimina este vector." },
    { q:"¿Qué es el 'shadow copy' y por qué los ransomware lo atacan?", o:["Una copia de seguridad en la nube","Las instantáneas de volumen (VSS) de Windows que permiten restaurar versiones anteriores de archivos; los ransomware las eliminan para impedir la recuperación sin pagar","Una copia espejo de disco RAID","El sistema de backup de Active Directory"], c:1, e:"Las Shadow Copies (VSS) de Windows son copias en punto en el tiempo que permiten restaurar archivos. Los ransomware modernos ejecutan 'vssadmin delete shadows /all' para eliminarlas, bloqueando la recuperación gratuita." },
    { q:"¿Qué es la 'segmentación de red' como defensa contra ransomware?", o:["Usar múltiples ISPs para redundancia","Dividir la red en zonas aisladas con controles de acceso entre ellas, de forma que el ransomware no pueda propagarse libremente a todos los sistemas","Segmentar el ancho de banda por departamento","Usar VLANs solo para separar voz y datos"], c:1, e:"La segmentación divide la red en zonas (usuarios, servidores, OT, DMZ, backups) con firewalls o controles entre ellas. Si el ransomware infecta un equipo de usuario, la segmentación evita que llegue a servidores o backups." },
    { q:"¿Cuál es el rol del EDR (Endpoint Detection and Response) en la defensa contra ransomware?", o:["Sustituye al antivirus tradicional sin capacidades adicionales","Detecta comportamientos maliciosos (cifrado masivo, eliminación de VSS, movimiento lateral) en tiempo real y permite contención automatizada antes de que el ransomware complete su ejecución","Solo detecta ransomware conocido por firmas","Es suficiente con un EDR sin otras defensas"], c:1, e:"El EDR detecta comportamientos característicos del ransomware (acceso masivo a archivos, llamadas a criptografía, eliminación de backups) y puede aislar automáticamente el endpoint afectado antes de que el daño sea total." },
    { q:"¿Qué es el 'lateral movement' en un ataque de ransomware y cómo se previene?", o:["El movimiento del ransomware entre archivos en el mismo equipo","El desplazamiento del atacante desde el sistema comprometido inicialmente hacia otros sistemas de la red usando credenciales robadas o vulnerabilidades; se previene con segmentación y mínimo privilegio","El movimiento de datos entre servidores durante la exfiltración","La propagación por USB entre equipos"], c:1, e:"El movimiento lateral usa herramientas como PsExec, WMI o Mimikatz para desplazarse a otros sistemas con credenciales robadas. Prevenirlo requiere: segmentación de red, mínimo privilegio, detección de uso anómalo de credenciales y MFA." },
    { q:"¿Por qué pagar el rescate no garantiza la recuperación de los datos?", o:["Porque la clave de descifrado siempre es incorrecta","Porque las organizaciones que pagan pueden no recibir la clave funcional, el descifrador puede fallar, los datos ya fueron exfiltrados, y el pago incentiva futuros ataques","Porque el pago es ilegal en todos los países","Porque los datos siempre quedan corruptos tras el cifrado"], c:1, e:"El FBI y CISA desaconsejan el pago: aproximadamente el 20-40% de las organizaciones que pagan no recuperan todos sus datos, el pago no elimina los datos exfiltrados, puede incumplir sanciones OFAC y financia la infraestructura criminal." },
    { q:"¿Qué es el 'backup inmutable' y por qué es esencial contra ransomware?", o:["Un backup que no se puede comprimir","Un backup que no puede ser modificado ni eliminado durante un período definido (WORM), incluso por administradores, garantizando su integridad ante un atacante con privilegios elevados","Un backup cifrado con clave del proveedor","Un backup automático sin intervención humana"], c:1, e:"Los backups inmutables (WORM - Write Once Read Many) no pueden ser modificados ni eliminados durante el período de retención definido. Son críticos porque los ransomware modernos intentan eliminar backups incluso con cuentas de administrador comprometidas." },
    { q:"¿Qué es el 'time to ransom' en un ataque de ransomware?", o:["El plazo para pagar el rescate","El tiempo desde el compromiso inicial hasta que el ransomware se ejecuta y cifra los datos","El tiempo de respuesta del equipo de IR","El tiempo total del incidente"], c:1, e:"El time to ransom es el tiempo entre el acceso inicial y la ejecución del cifrado. Ataques oportunistas pueden ser de horas; ataques APT planificados pueden tener time to ransom de semanas o meses (Akira, LockBit)." },
    { q:"¿Qué información debe preservarse para la forensia post-ransomware?", o:["Solo los archivos cifrados","Imágenes forenses de discos afectados, logs de sistemas, red y seguridad, memoria RAM de sistemas activos y evidencia de exfiltración, antes de comenzar la recuperación","Solo los logs del antivirus","El binario del ransomware únicamente"], c:1, e:"Para la forensia es crítico preservar: imágenes de disco, logs de sistemas, firewalls, AD, SIEM, capturas de memoria RAM (volátiles), pcap de red y todo lo que permita reconstruir el ataque antes de limpiar los sistemas." },
    { q:"¿Qué normativa española obliga a notificar incidentes de ransomware a las autoridades?", o:["Solo el RGPD si hay datos personales afectados","ENS (al CCN-CERT) si afecta a sistemas de AA.PP., NIS2 transpuesta si afecta a operadores incluidos, y RGPD si hay datos personales comprometidos","Solo el Código Penal","No existe obligación de notificación en España"], c:1, e:"En España, la notificación puede ser obligatoria bajo múltiples marcos: ENS al CCN-CERT (AA.PP.), la futura transposición de NIS2 al INCIBE-CERT (sectores críticos), y RGPD a la AEPD (si hay datos personales comprometidos)." },
    { q:"¿Qué es el 'pre-positioning' en un ataque de ransomware sofisticado?", o:["La configuración del servidor de C2 del atacante","El proceso de preparación del ataque: el actor ya dentro de la red instala herramientas, obtiene credenciales privilegiadas y posiciona el ransomware en múltiples sistemas antes de ejecutarlo simultáneamente","La fase de negociación del rescate","El escaneo inicial de puertos externos"], c:1, e:"En ataques APT de ransomware, el pre-positioning puede durar semanas: el atacante se mueve lateralmente, obtiene credenciales de admin, identifica los backups y sistemas críticos, y cuando activa el ransomware, lo hace de forma masiva y simultánea." },
    { q:"¿Por qué proteger Active Directory es prioritario en la defensa anti-ransomware?", o:["AD gestiona las licencias de software","AD controla la autenticación y autorización de toda la red corporativa. Si el atacante compromete AD (dominio admin), puede desplegar ransomware a todos los equipos simultáneamente via GPO","AD solo afecta a equipos Windows","AD es inmune al ransomware por diseño"], c:1, e:"Active Directory es el 'cerebro' de la red Windows: controla accesos, políticas y autenticación. Un atacante que compromete una cuenta de Domain Admin puede desplegar ransomware simultáneamente a todos los equipos vía GPO en minutos." },
    { q:"¿Qué es el 'Incident Response Retainer' y por qué es recomendable tenerlo antes de un incidente?", o:["Un seguro cibernético","Un contrato previo con una empresa de IR que garantiza respuesta rápida y prioridad ante un incidente, sin la demora y coste extra de negociar durante la crisis","Un retén de personal interno de seguridad 24/7","Un acuerdo de intercambio de información con el CERT nacional"], c:1, e:"El IR Retainer es un contrato pre-negociado con una empresa de respuesta a incidentes: garantiza SLAs de respuesta, familiarización previa con el entorno y precios acordados. Sin él, buscar ayuda durante la crisis es más lento y caro." },
    { q:"¿Qué herramienta de Microsoft ayuda a detectar movimiento lateral relacionado con ransomware en entornos Active Directory?", o:["Microsoft Defender Antivirus","Microsoft Defender for Identity (antes Azure ATP): detecta ataques como Pass-the-Hash, Kerberoasting y movimiento lateral en AD","Microsoft Intune","Azure Active Directory Connect"], c:1, e:"Microsoft Defender for Identity monitoriza el tráfico de AD y detecta ataques de credenciales (PtH, PtT, Kerberoasting, DCSync) y movimiento lateral, que son las técnicas previas habituales en despliegues de ransomware." },
    { q:"¿Qué es el 'grupo de negociación' de los operadores de ransomware modernos?", o:["El equipo legal de la víctima","Un equipo especializado del grupo criminal que gestiona la comunicación con las víctimas, negocia el importe del rescate y gestiona el pago en criptomonedas","Un intermediario legal","Las autoridades policiales que median"], c:1, e:"Los grupos de ransomware sofisticados (Akira, LockBit, BlackCat) tienen equipos dedicados de 'negociación' que contactan con las víctimas, establecen el importe según el tamaño de la empresa y gestionan el proceso de pago." },
    { q:"¿Qué es la 'caza de amenazas' (threat hunting) aplicada a la defensa anti-ransomware?", o:["Buscar el ransomware en foros de la dark web","La búsqueda proactiva de indicadores de compromiso (IOCs) y comportamientos anómalos en la red antes de que el ransomware se active, durante el período de dwell time","La actualización automática de firmas de antivirus","El análisis de malware en sandboxes"], c:1, e:"El threat hunting busca proactivamente señales de presencia del atacante durante el dwell time: cuentas inusuales, herramientas de reconocimiento (BloodHound, Mimikatz), accesos anómalos a backups, antes de que se active el cifrado." },
    { q:"¿Cuál es el impacto regulatorio de un ataque de ransomware que compromete datos personales?", o:["Ninguno si se paga el rescate y se recuperan los datos","El ransomware es por definición una brecha de seguridad bajo el RGPD, con obligación de notificación a la AEPD en 72 horas y potencialmente a los interesados, independientemente de si se pagan o recuperan los datos","Solo hay impacto si los datos se publican","Solo aplica en sectores regulados como banca o sanidad"], c:1, e:"Un ransomware que cifra datos personales es una brecha de confidencialidad, integridad y disponibilidad bajo el RGPD. Obliga a notificar a la AEPD en 72 horas y, si hay alto riesgo, a los afectados. El pago del rescate no elimina esta obligación." },
    { q:"¿Qué es el 'backup air-gapped' y cuándo está justificado?", o:["Un backup en la nube con acceso restringido","Una copia de seguridad físicamente aislada de toda red (sin conexión de red, incluso local), accesible solo físicamente; justificado para datos críticos donde el riesgo de compromiso del backup es inaceptable","Un backup en una VLAN separada","Un backup con autenticación de doble factor"], c:1, e:"Un backup air-gapped es físicamente desconectado de toda red: ni Internet, ni LAN, ni WiFi. Solo se conecta durante la ventana de backup y se desconecta inmediatamente. Máxima protección contra ransomware que compromete credenciales de administrador." },
    { q:"¿Qué lecciones aprendidas del caso SonicWall/Akira son aplicables a cualquier organización?", o:["Los appliances de red son inmunes al ransomware por diseño","Las vulnerabilidades en appliances de frontera (VPN/NGFW) sin parchear son vectores de entrada críticos; la segmentación y los IOCs del fabricante deben monitorizarse activamente","Solo los firewalls de gama baja son vulnerables","Los ataques a firewalls solo ocurren en entornos OT"], c:1, e:"Casos como SonicWall/Akira demuestran que los appliances de frontera (firewalls, VPN gateways) son objetivos prioritarios: explotan CVEs publicadas, suelen tener acceso privilegiado y conectividad total. El parcheo urgente y la monitorización de IOCs del fabricante son críticos." }
  ],

  // ══════════════════════════════════════════════════════════
  "vCISO / GRC": [
    { q:"¿Qué distingue a un vCISO de un CISO interno?", o:["El vCISO tiene menor experiencia","El vCISO presta servicios a múltiples organizaciones de forma externa y parcial, aportando visión de múltiples sectores sin el coste de una contratación a tiempo completo","El vCISO solo hace auditorías","El vCISO es un consultor sin responsabilidad ejecutiva"], c:1, e:"El vCISO (Virtual CISO) es un profesional de seguridad senior que actúa como CISO externo para una o varias organizaciones. Aporta experiencia multisectorial, flexibilidad y un coste menor que un CISO interno senior a tiempo completo." },
    { q:"¿Qué significa GRC en el contexto de ciberseguridad?", o:["Gestión de Riesgos Críticos","Governance, Risk and Compliance: el conjunto integrado de procesos para alinear TI con los objetivos de negocio, gestionar riesgos y cumplir con regulaciones","Gestión de Recursos de Ciberseguridad","Global Risk Control"], c:1, e:"GRC (Governance, Risk, Compliance) es el enfoque integrado que conecta la gobernanza corporativa, la gestión de riesgos y el cumplimiento normativo, asegurando que la seguridad esté alineada con los objetivos de negocio." },
    { q:"¿Cuál es el primer paso de un vCISO al incorporarse a una nueva organización?", o:["Implementar inmediatamente un SIEM","Realizar una evaluación de madurez (gap analysis) del estado actual de seguridad frente a un marco de referencia","Contratar un SOC externo","Redactar la política de seguridad desde cero"], c:1, e:"El primer paso es entender el estado actual: un gap analysis frente a ISO 27001, NIST CSF, ENS u otro marco relevante identifica brechas, prioriza acciones y establece la línea base desde la que medir el progreso." },
    { q:"¿Qué es el 'apetito de riesgo' en el contexto del GRC?", o:["El presupuesto máximo de ciberseguridad","La cantidad y tipo de riesgo que la organización está dispuesta a asumir en la búsqueda de sus objetivos estratégicos","El número de vulnerabilidades aceptables en un sistema","El tiempo máximo de interrupción tolerable"], c:1, e:"El apetito de riesgo es una decisión estratégica de la alta dirección: define cuánto riesgo es aceptable. El vCISO ayuda a cuantificarlo y a traducirlo en criterios operativos de aceptación de riesgos." },
    { q:"¿Qué es el NIST Cybersecurity Framework (CSF) y cuándo es más útil que ISO 27001?", o:["Es una norma certificable equivalente a ISO 27001","Es un marco voluntario de 5 funciones (Identificar, Proteger, Detectar, Responder, Recuperar) más flexible y comunicativo; más útil para organizaciones sin madurez para abordar ISO 27001 o que priorizan la comunicación ejecutiva del riesgo","Es un reglamento de EEUU sin aplicabilidad en Europa","Es exclusivo para infraestructuras críticas americanas"], c:1, e:"El NIST CSF es un marco voluntario, flexible y muy comunicativo. Es especialmente útil para comunicar el estado de madurez de ciberseguridad a la dirección, para organizaciones en fases iniciales o como complemento a ISO 27001." },
    { q:"¿Cómo debe comunicar el vCISO el riesgo a la alta dirección?", o:["En lenguaje técnico detallado para demostrar expertise","Traduciendo el riesgo técnico a impacto de negocio: coste económico, impacto regulatorio, reputacional y operativo, con métricas comprensibles para el perfil ejecutivo","Con informes de vulnerabilidades técnicas en crudo","Solo mediante dashboards automáticos del SIEM"], c:1, e:"El vCISO actúa como puente entre seguridad y negocio: traduce riesgos técnicos a impacto de negocio (€, reputación, multas, continuidad), usando lenguaje y métricas ejecutivas para facilitar decisiones informadas de la dirección." },
    { q:"¿Qué es un SGSI y cuál es el rol del vCISO en su implementación?", o:["Sistema de Gestión de Seguridad Informática, implementado solo por el departamento IT","Sistema de Gestión de Seguridad de la Información (ISO 27001): el vCISO lidera su diseño, implementación y auditoría, asegurando el compromiso de la dirección y la integración con el negocio","Un software de gestión de incidentes","Un registro de activos de información"], c:1, e:"El SGSI es el sistema de gestión basado en ISO 27001. El vCISO lidera el proyecto de implementación: define el alcance, gestiona el análisis de riesgos, coordina los controles, prepara las auditorías y mantiene el ciclo de mejora continua." },
    { q:"¿Qué es el 'mapa de calor de riesgos' (risk heat map) y para qué sirve?", o:["Un mapa geográfico de incidentes de ciberseguridad","Una representación visual que muestra los riesgos según su probabilidad e impacto, facilitando la priorización y la comunicación ejecutiva","Un inventario de vulnerabilidades técnicas","El dashboard del SIEM con alertas en tiempo real"], c:1, e:"El risk heat map representa los riesgos en una matriz probabilidad/impacto con colores (rojo/amarillo/verde). Es una herramienta de comunicación ejecutiva que facilita la priorización de tratamientos y la toma de decisiones." },
    { q:"¿Cuál es la diferencia entre una auditoría de cumplimiento y una evaluación de riesgos?", o:["Son el mismo proceso con diferente nombre","La auditoría verifica si los controles existen y cumplen un marco normativo; la evaluación de riesgos identifica y cuantifica los riesgos independientemente de si hay un marco que los exija","La evaluación de riesgos es realizada por externos; la auditoría por internos","Solo la auditoría genera evidencias documentadas"], c:1, e:"La auditoría de cumplimiento verifica conformidad con una norma (ISO 27001, ENS). La evaluación de riesgos identifica, analiza y prioriza riesgos de forma más amplia. Ambas son complementarias en el GRC." },
    { q:"¿Qué es la 'cadena de custodia' en el contexto de evidencias de seguridad?", o:["El proceso de aprobación de presupuesto de seguridad","El registro documentado e ininterrumpido que garantiza la integridad de una evidencia desde su obtención hasta su presentación, demostrando que no ha sido alterada","La jerarquía de responsabilidad del equipo de seguridad","El proceso de clasificación de activos de información"], c:1, e:"La cadena de custodia documenta quién ha tenido acceso a una evidencia, cuándo y cómo, garantizando su integridad e intacción. Es fundamental para que las evidencias sean admisibles en procedimientos legales o disciplinarios." },
    { q:"¿Qué es el 'tablero de indicadores de riesgo clave' (KRI) en GRC?", o:["Un dashboard de rendimiento del SOC","Métricas predictivas que señalan el aumento del nivel de riesgo antes de que se materialice, permitiendo actuación proactiva","El informe mensual de vulnerabilidades","Los KPIs del departamento de seguridad"], c:1, e:"Los KRIs son indicadores anticipadores del riesgo: muestran si el nivel de riesgo está aumentando antes de que ocurra el incidente. Ejemplos: % de sistemas sin parches, tiempo medio de resolución de vulnerabilidades críticas, número de accesos privilegiados sin revisar." },
    { q:"¿Qué es la 'gestión de excepciones' en un programa GRC?", o:["Gestionar los incidentes de seguridad","El proceso formal para documentar, aprobar y seguir los casos en que no se cumple un control de seguridad, con justificación de negocio, riesgo residual aceptado y plazo de resolución","La aprobación de cambios en sistemas críticos","El tratamiento de vulnerabilidades de día cero"], c:1, e:"La gestión de excepciones es fundamental en GRC: cuando un control no puede implementarse (legacy, coste, operativa), se documenta la excepción, se evalúa el riesgo residual, la dirección lo acepta explícitamente y se establece un plazo de revisión." },
    { q:"¿Cómo contribuye el vCISO a la selección y gestión de proveedores de seguridad?", o:["Solo valida las facturas del departamento de IT","Define los requisitos de seguridad técnicos y normativos, evalúa la madurez de seguridad de los proveedores y supervisa su cumplimiento contractual (TPRM)","Gestiona las relaciones comerciales con los proveedores","Solo actúa cuando hay un incidente con un proveedor"], c:1, e:"El vCISO lidera el TPRM (Third Party Risk Management): define criterios de seguridad para proveedores, realiza o supervisa cuestionarios de seguridad, revisa sus certificaciones y garantiza que los contratos incluyen cláusulas de seguridad adecuadas." },
    { q:"¿Qué es el 'programa de concienciación en seguridad' y por qué es responsabilidad del vCISO?", o:["Un programa de formación técnica para el equipo de IT","Un programa continuo que desarrolla la cultura de seguridad de toda la organización (phishing simulado, formaciones, comunicaciones) para reducir el riesgo humano, que sigue siendo el mayor vector de ataque","Un curso anual obligatorio de protección de datos","La certificación del personal de seguridad"], c:1, e:"El vCISO diseña y supervisa el programa de concienciación: es la defensa más coste-efectiva contra el phishing y la ingeniería social, que son los principales vectores de ataque. Incluye formaciones, simulaciones y cultura de seguridad." },
    { q:"¿Qué es el 'informe ejecutivo de seguridad' y cuál debe ser su estructura?", o:["Un informe técnico detallado de vulnerabilidades","Un informe periódico para la dirección que resume el estado del SGSI, incidentes, métricas de riesgo, progreso del roadmap y decisiones pendientes, en lenguaje de negocio sin jerga técnica","El resultado de la auditoría interna","El dashboard del SIEM en PDF"], c:1, e:"El informe ejecutivo traduce la seguridad al lenguaje de negocio: estado del riesgo, incidentes relevantes, métricas de madurez, progreso del plan, inversiones realizadas y decisiones que requieren aprobación. Su audiencia es la dirección y el consejo." },
    { q:"¿Cuándo tiene sentido para una PYME contratar un vCISO en lugar de un CISO interno?", o:["Nunca; las PYMEs no necesitan CISO","Cuando el volumen de trabajo de seguridad no justifica un dedicación completa, pero la organización necesita expertise senior para cumplimiento normativo, gestión de riesgos y respuesta a incidentes","Solo cuando hay un incidente grave","Cuando el CISO interno está de vacaciones"], c:1, e:"Para PYMEs, el vCISO ofrece expertise senior sin el coste de una contratación a tiempo completo. Tiene sentido cuando hay obligaciones de compliance (ENS, NIS2, ISO 27001) o riesgos significativos que requieren dirección estratégica de seguridad." },
    { q:"¿Qué es el 'roadmap de seguridad' y cómo lo construye el vCISO?", o:["El inventario de herramientas de seguridad a comprar","El plan estratégico plurianual que prioriza las iniciativas de seguridad según el riesgo, el impacto en el negocio y los recursos disponibles, alineado con la estrategia de negocio","El calendario de auditorías anuales","La hoja de ruta de certificaciones del equipo de IT"], c:1, e:"El roadmap de seguridad es el plan estratégico del SGSI: prioriza iniciativas (qué hacer primero), define hitos, asigna recursos y mide el progreso. El vCISO lo construye desde el gap analysis, alineándolo con el apetito de riesgo y los objetivos de negocio." },
    { q:"¿Qué es el 'modelo RACI' aplicado a la gestión de seguridad?", o:["Un framework de evaluación de riesgos","Una matriz que define para cada proceso o control quién es Responsable, quién rinde cuentas (Accountable), quién es Consultado y quién es Informado","Un modelo de contratación de CISO","Un estándar de clasificación de activos"], c:1, e:"La matriz RACI (Responsible, Accountable, Consulted, Informed) es fundamental en GRC: aclara quién hace qué en cada proceso de seguridad, evitando ambigüedades y vacíos de responsabilidad que son causas frecuentes de fallos de control." },
    { q:"¿Cómo debe el vCISO demostrar el valor de la inversión en seguridad (ROI)?", o:["Mostrando el coste de las herramientas compradas","Cuantificando la reducción de riesgo (en €), el coste evitado de incidentes, el valor del cumplimiento normativo (multas evitadas) y la mejora de la postura de seguridad medida con KPIs","Con el número de alertas gestionadas por el SOC","Con el número de vulnerabilidades parcheadas"], c:1, e:"El ROI en seguridad se demuestra cuantificando: riesgo reducido (probabilidad × impacto antes/después), coste de incidentes evitados (benchmarks sectoriales), multas regulatorias evitadas y el valor de la confianza de clientes y socios." },
    { q:"¿Qué es el 'plan director de seguridad' en el contexto del vCISO?", o:["El presupuesto anual de IT","El documento estratégico que integra el análisis de situación actual, los objetivos de seguridad, las iniciativas priorizadas, el presupuesto y los indicadores de progreso a 2-3 años","El plan de respuesta a incidentes","La política de seguridad de la información"], c:1, e:"El plan director de seguridad es el documento maestro del programa de seguridad: diagnóstico actual, objetivos estratégicos, proyectos priorizados, hitos, recursos necesarios y KPIs. El vCISO lo diseña, lo presenta a la dirección y lo ejecuta." },
    { q:"¿Qué diferencia el GRC reactivo del GRC proactivo?", o:["El reactivo es más barato siempre","El GRC reactivo responde a incidentes y auditorías; el proactivo anticipa riesgos, mejora continuamente controles y alinea seguridad con negocio antes de que los problemas ocurran","Solo el GRC reactivo es efectivo en PYMEs","El GRC proactivo solo aplica a grandes corporaciones"], c:1, e:"El GRC reactivo actúa cuando hay un problema (incidente, auditoría fallida). El GRC proactivo del GRCREAL de Miguel Ángel anticipa riesgos, mide continuamente la madurez y mejora los controles antes de que los problemas se materialicen." },
    { q:"¿Qué es la 'madurez del SGSI' y cómo se mide?", o:["El número de años de certificación ISO 27001","El nivel de implementación, integración y mejora continua del SGSI, medido con modelos como CMM (1-5 niveles) o el modelo de madurez del NIST CSF","El número de controles implementados","El tamaño del equipo de seguridad"], c:1, e:"La madurez del SGSI mide cuán bien integrada, documentada, medida y mejorada está la seguridad. Los modelos más usados son el CMM (5 niveles: inicial, gestionado, definido, cuantificado, optimizado) y el modelo de madurez del NIST CSF." },
    { q:"¿Cómo aborda el vCISO la gestión del riesgo de la cadena de suministro?", o:["Delegando completamente en el departamento de compras","Implementando un programa TPRM: identificar proveedores críticos, evaluar su seguridad, incluir cláusulas contractuales y monitorizar continuamente su postura de seguridad","Solo revisando las certificaciones ISO de los proveedores","Limitando el acceso de todos los proveedores a la red"], c:1, e:"El vCISO lidera el TPRM (Third Party Risk Management): clasifica proveedores por criticidad, realiza due diligence de seguridad, negocia cláusulas contractuales (auditoría, incidentes, continuidad) y establece monitorización continua." },
    { q:"¿Qué es la 'política de seguridad de la información' y qué debe incluir?", o:["Un manual técnico de procedimientos de seguridad","Un documento aprobado por la dirección que establece la intención y el compromiso de la organización con la seguridad, los principios, responsabilidades y el marco de referencia, revisado periódicamente","La lista de controles del Anexo A implementados","El reglamento de uso de TI para empleados"], c:1, e:"La política de seguridad (ISO 27001, cláusula 5.2) es el documento de más alto nivel del SGSI: expresa el compromiso de la dirección, define principios, asigna responsabilidades y establece el marco. Es pública para las partes interesadas y revisada periódicamente." },
    { q:"¿Qué es el 'compliance mapping' en el trabajo del vCISO?", o:["Un mapa de los sistemas del cliente","El proceso de identificar cómo los controles existentes cubren múltiples marcos normativos simultáneamente (ISO 27001, ENS, NIS2, RGPD), evitando duplicidades y optimizando el esfuerzo de cumplimiento","El registro de auditorías de cumplimiento pasadas","La asignación de presupuesto por normativa"], c:1, e:"El compliance mapping identifica qué controles satisfacen simultáneamente varios marcos (ej: un control de gestión de accesos puede satisfacer ISO 27001 A.8.3, ENS op.acc.4 y NIS2 art. 21), optimizando el esfuerzo y evitando duplicar trabajo." },
    { q:"¿Qué habilidades blandas son críticas para un vCISO efectivo además del conocimiento técnico?", o:["Solo el conocimiento técnico es relevante","Comunicación ejecutiva, gestión del cambio, liderazgo sin autoridad directa, negociación y capacidad de construir relaciones de confianza con la dirección y los equipos","Habilidades de programación","Conocimiento contable y financiero avanzado"], c:1, e:"El vCISO actúa en múltiples frentes: convence a la dirección de invertir en seguridad, coordina equipos sin autoridad directa, gestiona expectativas de múltiples stakeholders y traduce complejidad técnica a decisiones de negocio. Las habilidades blandas son tan críticas como las técnicas." },
    { q:"¿Qué es el 'modelo GRCREAL' en el contexto de la consultoría de seguridad?", o:["Un framework de certificación de CISOs","Un enfoque que trata el GRC como una capacidad operativa continua y real, no como un proyecto puntual o ejercicio de checkbox compliance, integrando seguridad en el negocio de forma genuina","Un estándar ISO alternativo","Un modelo de precios de consultoría"], c:1, e:"GRCREAL es el marco de Miguel Ángel Carriazo que posiciona el GRC como capacidad operativa continua: no es un proyecto de certificación o un ejercicio de cumplimiento formal, sino la integración real y sostenida de la seguridad en los procesos de negocio." }
  ],

  // ══════════════════════════════════════════════════════════
  "Threat Intelligence": [
    { q:"¿Qué es la inteligencia de amenazas (Threat Intelligence)?", o:["El análisis de logs del SIEM","Información contextualizada sobre amenazas actuales o potenciales que, una vez analizada, permite tomar decisiones de seguridad más informadas y proactivas","Un escáner de vulnerabilidades automatizado","El informe mensual de incidentes"], c:1, e:"La Threat Intelligence es información analizada y contextualizada sobre actores de amenaza, sus TTPs (tácticas, técnicas y procedimientos), infraestructura y objetivos, que permite anticipar y mitigar ataques." },
    { q:"¿Cuáles son los 4 niveles de madurez de la inteligencia de amenazas?", o:["Básico, intermedio, avanzado y experto","Estratégica, operacional, táctica y técnica","Descriptiva, diagnóstica, predictiva y prescriptiva","Reactiva, proactiva, preventiva y predictiva"], c:1, e:"La TI se organiza en 4 niveles: Estratégica (tendencias para la dirección), Operacional (campañas activas para SOC/IR), Táctica (TTPs de actores para controles) y Técnica (IOCs específicos: IPs, hashes, dominios)." },
    { q:"¿Qué es el framework MITRE ATT&CK?", o:["Una norma de certificación de analistas de threat intelligence","Una base de conocimiento de TTPs (tácticas, técnicas y procedimientos) de actores reales, organizada por fases del ciclo de ataque, usada para mapear ataques, mejorar detecciones y evaluar cobertura defensiva","Un escáner de vulnerabilidades","Un marco de cumplimiento normativo"], c:1, e:"MITRE ATT&CK es una base de conocimiento pública de TTPs reales de actores de amenaza, organizada en matrices (Enterprise, Mobile, ICS). Es el estándar de facto para mapear comportamientos de atacantes y evaluar cobertura de detección." },
    { q:"¿Qué es un IOC (Indicator of Compromise)?", o:["Un indicador de rendimiento del SIEM","Un artefacto forense (IP, dominio, hash, URL, firma) que indica con alta probabilidad que un sistema ha sido comprometido o está en contacto con infraestructura maliciosa","Una vulnerabilidad sin parche conocido","Una alerta de falso positivo del antivirus"], c:1, e:"Los IOCs son artefactos técnicos que señalan compromiso: hashes de malware, IPs de C2, dominios maliciosos, rutas de archivos, claves de registro. Son el nivel más operacional de TI y pueden bloquearse directamente en controles de seguridad." },
    { q:"¿Qué es el modelo Diamond de inteligencia de amenazas?", o:["Un modelo de madurez de SOC","Un modelo analítico que relaciona 4 elementos de un ataque: adversario, infraestructura, capacidades y víctima, ayudando a entender y correlacionar incidentes","Un framework de clasificación de vulnerabilidades","Un método de priorización de alertas"], c:1, e:"El Modelo Diamond analiza los ataques mediante 4 vértices: Adversario (quien ataca), Infraestructura (cómo), Capacidades (TTPs) y Víctima (objetivo). Permite correlacionar ataques y atribuirlos a actores conocidos." },
    { q:"¿Qué es el ciclo de vida de la inteligencia de amenazas?", o:["El proceso de renovación de licencias de herramientas TI","El proceso iterativo de Planificación, Recolección, Procesamiento, Análisis, Difusión y Retroalimentación que convierte datos brutos en inteligencia accionable","El ciclo de respuesta a incidentes","El proceso de gestión de vulnerabilidades"], c:1, e:"El ciclo de TI (Intelligence Lifecycle) convierte datos en inteligencia: Planificación (qué necesito saber) → Recolección → Procesamiento → Análisis → Difusión (al público adecuado) → Retroalimentación (¿fue útil?)." },
    { q:"¿Qué diferencia a los IOCs de los TTPs en inteligencia de amenazas?", o:["Los IOCs son más útiles que los TTPs siempre","Los IOCs son efímeros (el atacante los cambia fácilmente); los TTPs son comportamientos más persistentes y costosos de cambiar para el atacante, siendo más valiosos para la detección a largo plazo","Los TTPs son solo para inteligencia estratégica","Los IOCs aplican a malware; los TTPs solo a actores APT"], c:1, e:"Los IOCs (IPs, dominios, hashes) se cambian fácilmente en horas. Los TTPs (cómo ataca el actor) son comportamientos que tardan meses en cambiar. Detectar TTPs es más resiliente: no depende de conocer el IOC exacto." },
    { q:"¿Qué es un feed de threat intelligence y cuáles son sus limitaciones?", o:["Un informe mensual de amenazas","Un flujo automatizado de IOCs e indicadores de amenaza; su limitación es que sin contextualización y verificación genera falsos positivos, sobrecarga los controles y puede degradar la detección","Una plataforma de gestión de vulnerabilidades","Un canal de comunicación del CERT"], c:1, e:"Los feeds TI son flujos de IOCs (IPs, hashes, URLs maliciosas). Su limitación: sin contextualización, verificación de relevancia y limpieza generan ruido masivo, falsos positivos y fatiga de alertas. La calidad es más importante que el volumen." },
    { q:"¿Qué es TAXII/STIX en el contexto de threat intelligence?", o:["Un escáner de vulnerabilidades de código abierto","STIX es el formato estándar para representar inteligencia de amenazas; TAXII es el protocolo de transporte para compartirla entre organizaciones y plataformas","Un sistema de gestión de incidentes","Dos plataformas TIP competidoras"], c:1, e:"STIX (Structured Threat Information Expression) es el formato XML/JSON estándar para describir indicadores, actores, TTPs y campañas. TAXII (Trusted Automated eXchange of Intelligence Information) es el protocolo para intercambiarlos entre organizaciones." },
    { q:"¿Qué es una TIP (Threat Intelligence Platform)?", o:["Un proveedor de servicios de inteligencia","Una plataforma que agrega, normaliza, enriquece y distribuye inteligencia de amenazas, integrándola con SIEM, firewalls y otras herramientas de seguridad","El sistema de ticketing del SOC","Una herramienta de pentesting"], c:1, e:"Una TIP (como MISP, OpenCTI, ThreatConnect) centraliza la gestión de TI: agrega feeds, enriquece IOCs con contexto, elimina duplicados y falsos positivos, y distribuye inteligencia accionable a los controles de seguridad." },
    { q:"¿Qué es la inteligencia de fuentes abiertas (OSINT) aplicada a amenazas?", o:["Solo la información de Google","Información recopilada de fuentes públicas (redes sociales, foros, dark web, publicaciones técnicas, repositorios) para construir inteligencia sin necesidad de acceso privilegiado","Un método de ataque de phishing","El análisis de logs propios de la organización"], c:1, e:"OSINT para TI incluye: monitorización de foros de actores de amenaza, dark web, repositorios de malware (VirusTotal, MalwareBazaar), publicaciones de CERTs, cuentas de Twitter/X de investigadores, código en GitHub, etc." },
    { q:"¿Qué es el 'threat hunting' y cómo usa la inteligencia de amenazas?", o:["La búsqueda automatizada de malware con antivirus","La búsqueda proactiva de amenazas no detectadas en la red, guiada por hipótesis basadas en TTPs e IOCs conocidos, buscando signos de compromiso que los controles automáticos no han detectado","La gestión de alertas del SOC","El análisis de vulnerabilidades en aplicaciones web"], c:1, e:"El threat hunting usa TI (TTPs de actores relevantes, IOCs recientes) para formular hipótesis ('¿está Akira en nuestra red?') y buscar evidencias de esas TTPs en los datos propios, detectando amenazas que evaden los controles automáticos." },
    { q:"¿Qué información incluye un perfil de actor de amenaza (threat actor profile)?", o:["Solo los malwares que utiliza","Identificación del actor, motivaciones (financiera, espionaje, hackitivismo), objetivos sectoriales y geográficos, TTPs documentadas (MITRE ATT&CK), infraestructura conocida y campañas documentadas","Solo los IOCs asociados","Su identidad real y ubicación física"], c:1, e:"Un perfil de actor TI incluye: identificación (alias), motivaciones, sectores objetivo, TTPs (mapeadas en ATT&CK), infraestructura (dominios, IPs, herramientas), campañas conocidas y niveles de sofisticación." },
    { q:"¿Qué es el análisis de malware en el contexto de TI?", o:["Instalar el malware en un equipo de producción para analizarlo","El análisis estático (sin ejecutar: strings, imports, estructura) y dinámico (en sandbox: comportamiento en ejecución) del malware para extraer IOCs, TTPs y entender su funcionamiento","Solo el análisis de logs del antivirus","La búsqueda de malware en VirusTotal"], c:1, e:"El análisis de malware combina: estático (sin ejecutar: strings, imports, ofuscación, metadatos) y dinámico (en sandbox como Cuckoo, Any.run: comportamiento, C2, modificaciones del sistema). El resultado son IOCs y TTPs accionables." },
    { q:"¿Qué es el 'attribution' en inteligencia de amenazas y por qué es difícil?", o:["Identificar el malware utilizado en un ataque","Determinar quién está detrás de un ataque (actor, Estado, grupo criminal); es difícil porque los actores usan falsas banderas, infraestructura compartida, herramientas comunes y técnicas de anonimización","Clasificar el tipo de ataque","Calcular el impacto económico del ataque"], c:1, e:"La atribución en TI intenta vincular un ataque a un actor específico usando TTPs, infraestructura y comportamientos. Es compleja y raramente definitiva: los actores usan herramientas comunes, redirigen a través de otros sistemas y emplean falsas banderas deliberadas." },
    { q:"¿Qué es el 'sharing' de inteligencia de amenazas y por qué es valioso?", o:["La publicación de todos los incidentes de la organización","El intercambio de TI (IOCs, TTPs, contexto) entre organizaciones de confianza o a través de plataformas como MISP o ISACs, multiplicando el valor de la inteligencia al combinar visibilidad de múltiples fuentes","La venta de datos de incidentes a proveedores","El intercambio solo dentro del mismo grupo empresarial"], c:1, e:"El sharing multiplica el valor de la TI: lo que una organización ve en su red, combinado con lo que ven otras, crea una imagen más completa del panorama de amenazas. Las ISACs (por sector) y plataformas como MISP facilitan este intercambio." },
    { q:"¿Qué es el contexto en una pieza de inteligencia de amenazas y por qué es esencial?", o:["La fecha de publicación del indicador","La información que explica la relevancia de un IOC o TTP: qué actor lo usa, en qué campañas, contra qué sectores, con qué propósito; sin contexto, un IOC es solo un dato sin valor accionable","El formato técnico del indicador (STIX, CSV)","La fuente que lo publicó originalmente"], c:1, e:"Sin contexto, un hash o una IP son datos, no inteligencia. El contexto responde: ¿quién usa este IOC?, ¿en qué campañas?, ¿contra qué objetivos?, ¿qué significa detectarlo?. Solo con contexto puede tomarse una decisión de seguridad informada." },
    { q:"¿Cómo se usa MITRE ATT&CK para mejorar las capacidades de detección del SOC?", o:["Como inventario de herramientas de atacantes","Mapeando las técnicas ATT&CK cubiertas por las reglas de detección del SIEM y los controles, identificando los gaps (técnicas sin cobertura) y priorizando la creación de nuevas reglas de detección para las TTPs más relevantes para la organización","Como base de datos de IOCs","Como catálogo de vulnerabilidades a parchear"], c:1, e:"El mapeo ATT&CK permite visualizar qué técnicas detecta el SIEM (cobertura) y cuáles no. Priorizando las TTPs usadas por actores relevantes para la organización/sector, el SOC puede mejorar sistemáticamente su cobertura de detección." },
    { q:"¿Qué es la inteligencia sobre la dark web en el contexto de TI?", o:["Hacking de foros de la dark web","La monitorización de foros, mercados y canales de comunicación de actores de amenaza en la dark web para detectar credenciales robadas, datos de la organización a la venta, anuncios de ataques planificados o venta de accesos","La compra de exploits en la dark web","El uso de Tor para comunicaciones seguras"], c:1, e:"La monitorización de dark web permite detectar: credenciales de empleados comprometidas, datos de la organización publicados post-brecha, anuncios de ataques, accesos iniciales a la venta (IABs) o menciones de la organización como objetivo." },
    { q:"¿Qué es un 'Initial Access Broker' (IAB) y cuál es su relevancia para TI?", o:["Un consultor de seguridad especializado en pentesting","Un actor criminal que se especializa en obtener acceso inicial a organizaciones y vende ese acceso en foros de la dark web a otros actores (como grupos de ransomware), siendo un indicador temprano de un ataque inminente","Un proveedor de inteligencia de amenazas comercial","Un honeypot diseñado para atraer atacantes"], c:1, e:"Los IABs compran y venden accesos iniciales a organizaciones comprometidas. Detectar que el acceso a tu organización está a la venta en la dark web es una alerta temprana crítica: el grupo de ransomware puede estar a días de activarse." },
    { q:"¿Qué métricas miden la eficacia de un programa de threat intelligence?", o:["Solo el número de IOCs procesados","Tasa de verdaderos positivos de IOCs, tiempo de detección reducido, IOCs actionables vs. total, cobertura de TTPs relevantes en detecciones, y feedback de los equipos consumidores de la inteligencia","El número de feeds de TI contratados","El presupuesto invertido en TI"], c:1, e:"La eficacia de TI se mide cualitativamente y cuantitativamente: % de IOCs que generan detecciones reales, reducción del MTTD, % de TTPs de actores relevantes cubiertos, satisfacción de los equipos consumidores y casos de uso completados." },
    { q:"¿Qué es el 'pivoting' en investigación de inteligencia de amenazas?", o:["Cambiar de herramienta de análisis durante una investigación","La técnica de usar un indicador conocido (IP, dominio, hash) para descubrir indicadores relacionados, ampliando el conocimiento de la infraestructura y las campañas del actor","El proceso de cambiar de proveedor de TI","La rotación de analistas en el SOC"], c:1, e:"El pivoting en TI usa un IOC conocido como punto de partida para descubrir infraestructura relacionada: una IP maliciosa puede llevar a dominios registrados por el mismo actor, que a su vez revela más IPs y otras campañas." },
    { q:"¿Cómo contribuye la TI a la respuesta a incidentes?", o:["Solo sirve para prevención, no para IR","La TI acelera la respuesta: contextualiza el malware detectado (actor, TTPs, alcance típico), sugiere IOCs adicionales a buscar, informa sobre el comportamiento esperado del actor y sus técnicas de persistencia","Solo la TI técnica (IOCs) es útil en IR, no la estratégica","La TI solo es relevante post-incidente para el informe final"], c:1, e:"En IR, la TI acorta el tiempo de investigación: identifica el actor responsable, sus TTPs conocidas (qué más puede haber hecho), IOCs adicionales a buscar en la red, técnicas de persistencia típicas y si hay datos exfiltrados publicados." },
    { q:"¿Qué es el 'Pyramid of Pain' de David Bianco y cómo se aplica a TI?", o:["Una metodología de priorización de vulnerabilidades","Un modelo que clasifica los tipos de indicadores (hash, IP, dominio, artefacto de red, TTP) según el esfuerzo que cuesta al atacante cambiarlos; cuanto más arriba en la pirámide, más valioso y persistente es el indicador para la defensa","Un modelo de madurez del SOC","Una taxonomía de actores de amenaza"], c:1, e:"La Pyramid of Pain muestra que los IOCs técnicos (hashes, IPs) son fáciles de cambiar para el atacante (poco dolor). Los TTPs son difíciles y costosos de cambiar (mucho dolor). Detectar y bloquear TTPs es más resiliente que bloquear IPs o hashes." }
  ]

};

